    def open_fee_schedule_window(self):
        """Open the Fee Schedule search as a separate, non-modal window."""
        try:
            if not hasattr(self, "_child_windows"):
                self._child_windows = []
            dlg = FeeScheduleDialog(self)
            try:
                dlg.setModal(False)
                dlg.setWindowModality(Qt.WindowModality.NonModal)
            except Exception:
                pass
            dlg.setAttribute(Qt.WidgetAttribute.WA_DeleteOnClose)
            self._child_windows.append(dlg)
            dlg.show()
            try:
                dlg.raise_(); dlg.activateWindow()
            except Exception:
                pass
            def _cleanup(*_):
                try:
                    if dlg in self._child_windows:
                        self._child_windows.remove(dlg)
                except Exception:
                    pass
            dlg.finished.connect(_cleanup)
        except Exception as e:
            QMessageBox.warning(self, "Fee Schedule", f"Could not open Fee Schedule: {e}")

    def on_pickup_toggled(self, state):
        """Enforce that a Delivery/Pickup Date is set when 'Picked Up' is checked."""
        try:
            checked = bool(state)
            if not checked:
                return
            # Determine if the date field is effectively blank (we use 2000-01-01 as the blank sentinel)
            current = self.delivery_date_edit.date() if hasattr(self, 'delivery_date_edit') else None
            is_blank = True
            try:
                is_blank = (not current or not current.isValid() or current.year() <= 1901 or (current.year() == 2000 and current.month() == 1 and current.day() == 1))
            except Exception:
                is_blank = True

            if is_blank:
                reply = QMessageBox.question(
                    self,
                    "Delivery/Pickup Date Required",
                    (
                        "When marking an order as Picked Up, a Delivery/Pickup Date is required.\n\n"
                        "Set the date to today? You can adjust it after."
                    ),
                    QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                    QMessageBox.StandardButton.Yes,
                )
                if reply == QMessageBox.StandardButton.Yes:
                    self.delivery_date_edit.setDate(QDate.currentDate())
                    self.delivery_date_edit.setFocus()
                else:
                    # Revert the checkbox if user declined
                    try:
                        self.pickup_checkbox.blockSignals(True)
                        self.pickup_checkbox.setChecked(False)
                    finally:
                        try:
                            self.pickup_checkbox.blockSignals(False)
                        except Exception:
                            pass
                    # Bring focus to the date edit so user can pick
                    self.delivery_date_edit.setFocus()
        except Exception as e:
            # Non-fatal: just print to console
            print(f"Dialog: on_pickup_toggled error: {e}")

    def on_paid_toggled(self, state):
        """Enforce that a Paid Date is set when 'Paid' is checked."""
        try:
            checked = bool(state)
            if not checked:
                # Sync Orders table if editing an existing order
                try:
                    self._sync_orders_table_checkbox(14, False)
                except Exception:
                    pass
                return
            current = self.paid_date_edit.date() if hasattr(self, 'paid_date_edit') else None
            is_blank = True
            try:
                is_blank = (not current or not current.isValid() or current.year() <= 1901 or (current.year() == 2000 and current.month() == 1 and current.day() == 1))
            except Exception:
                is_blank = True

            if is_blank:
                reply = QMessageBox.question(
                    self,
                    "Paid Date Required",
                    (
                        "When marking an order as Paid, a Paid Date is required.\n\n"
                        "Set the date to today? You can adjust it after."
                    ),
                    QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                    QMessageBox.StandardButton.Yes,
                )
                if reply == QMessageBox.StandardButton.Yes:
                    self.paid_date_edit.setDate(QDate.currentDate())
                    self.paid_date_edit.setFocus()
                else:
                    try:
                        self.paid_checkbox.blockSignals(True)
                        self.paid_checkbox.setChecked(False)
                    finally:
                        try:
                            self.paid_checkbox.blockSignals(False)
                        except Exception:
                            pass
                    self.paid_date_edit.setFocus()
                    return

            # Sync Orders table if editing an existing order
            try:
                # Ensure table's Paid Date cell has the same date so parent won't prompt
                if hasattr(self, 'parent') and hasattr(self.parent, 'orders_table') and self.current_order_id:
                    order_num = None
                    try:
                        order_num = self.parent.format_order_number(int(self.current_order_id))
                    except Exception:
                        order_num = f"ORD-{str(int(self.current_order_id)).zfill(3)}"
                    for r in range(self.parent.orders_table.rowCount()):
                        d = self.parent.orders_table.item(r, 0)
                        if d and d.text() == order_num:
                            # Set Paid Date cell first to avoid prompt in parent handler
                            pd_item = self.parent.orders_table.item(r, 15)
                            if pd_item is None:
                                pd_item = QTableWidgetItem("")
                                self.parent.orders_table.setItem(r, 15, pd_item)
                            # Format date as yyyy-MM-dd to match parent expectations
                            qd = self.paid_date_edit.date()
                            date_str = qd.toString("yyyy-MM-dd") if qd and qd.isValid() else ""
                            pd_item.setText(date_str)
                            break
                # Now set the Paid selector in table (col 14) to Yes
                try:
                    for r in range(self.parent.orders_table.rowCount()):
                        d = self.parent.orders_table.item(r, 0)
                        if d and d.text() == order_num:
                            it = self.parent.orders_table.item(r, 14)
                            if it is None:
                                it = QTableWidgetItem("No")
                                self.parent.orders_table.setItem(r, 14, it)
                            it.setText("Yes")
                            break
                except Exception:
                    pass
            except Exception:
                pass
        except Exception as e:
            print(f"Dialog: on_paid_toggled error: {e}")

    # ----- Locking helpers -----
    def update_lock_state_prescriber(self, locked: bool):
        try:
            self.prescriber_combo.setEnabled(not locked)
            self.new_prescriber_btn.setEnabled(not locked)
            # Button icon/text
            self.lock_prescriber_btn.setText("🔒" if locked else "🔓")
        except Exception:
            pass

    def update_lock_state_patient(self, locked: bool):
        try:
            # Disable search + selection when locked
            self.patient_search.setEnabled(not locked)
            self.patient_combo.setEnabled(not locked)
            self.new_patient_btn.setEnabled(not locked)
            self.lock_patient_btn.setText("🔒" if locked else "🔓")
        except Exception:
            pass

    def update_lock_state_items(self, locked: bool):
        try:
            # Disable selection, add/remove, and table editing when locked
            self.item_combo.setEnabled(not locked)
            self.add_item_btn.setEnabled(not locked)
            self.remove_item_btn.setEnabled(not locked)
            self.items_table.setDisabled(locked)
            self.lock_items_btn.setText("🔒" if locked else "🔓")
        except Exception:
            pass

    def set_initial_locks(self):
        """Auto-lock key fields when editing an existing order."""
        try:
            if self.current_order_id:
                for btn, updater in (
                    (self.lock_prescriber_btn, self.update_lock_state_prescriber),
                    (self.lock_patient_btn, self.update_lock_state_patient),
                    (self.lock_items_btn, self.update_lock_state_items),
                ):
                    try:
                        btn.blockSignals(True)
                        btn.setChecked(True)
                    finally:
                        btn.blockSignals(False)
                    updater(True)
            else:
                # New order: start unlocked
                self.update_lock_state_prescriber(False)
                self.update_lock_state_patient(False)
                self.update_lock_state_items(False)
        except Exception:
            pass

