    # =========================
    # Patient Documents: DB + UI Handlers
    # =========================
    def ensure_patient_documents_table(self):
        try:
            conn = sqlite3.connect(self.patient_database_file)
            cur = conn.cursor()
            cur.execute(
                """
                CREATE TABLE IF NOT EXISTS patient_documents (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    patient_id INTEGER NOT NULL,
                    description TEXT,
                    original_name TEXT,
                    stored_path TEXT,
                    created_at TEXT DEFAULT (datetime('now'))
                )
                """
            )
            conn.commit()
            conn.close()
        except Exception as e:
            print(f"ensure_patient_documents_table failed: {e}")

    def _patient_documents_base_dir(self) -> str:
        try:
            base = None
            if isinstance(self.settings, dict):
                base = self.settings.get('db_folder')
            if not base:
                base = os.path.dirname(os.path.abspath(__file__))
            out = os.path.join(base, 'PatientDocuments')
            os.makedirs(out, exist_ok=True)
            return out
        except Exception:
            return os.getcwd()

    def _patient_documents_folder(self, patient_id: int) -> str:
        base = self._patient_documents_base_dir()
        folder = os.path.join(base, str(patient_id))
        try:
            os.makedirs(folder, exist_ok=True)
        except Exception:
            pass
        return folder

    def load_patient_documents(self, patient_id: int):
        try:
            if not hasattr(self, 'patient_documents_table'):
                return
            table = self.patient_documents_table
            table.setRowCount(0)
            conn = sqlite3.connect(self.patient_database_file)
            cur = conn.cursor()
            cur.execute(
                "SELECT id, description, original_name, stored_path, created_at FROM patient_documents WHERE patient_id = ? ORDER BY created_at DESC",
                (int(patient_id),),
            )
            rows = cur.fetchall()
            conn.close()
            for row in rows:
                rec_id, desc, orig, path, created = row
                r = table.rowCount()
                table.insertRow(r)
                item_desc = QTableWidgetItem(desc or '')
                item_file = QTableWidgetItem(orig or os.path.basename(path or '') or '')
                item_added = QTableWidgetItem(created or '')
                # Store metadata for actions
                item_desc.setData(Qt.ItemDataRole.UserRole, rec_id)
                item_desc.setData(Qt.ItemDataRole.UserRole + 1, path or '')
                table.setItem(r, 0, item_desc)
                table.setItem(r, 1, item_file)
                table.setItem(r, 2, item_added)
            try:
                table.resizeColumnsToContents()
            except Exception:
                pass
        except Exception as e:
            print(f"load_patient_documents failed: {e}")

    def add_patient_document(self):
        try:
            # Defensive: ensure table exists in case of first-run race
            try:
                self.ensure_patient_documents_table()
            except Exception:
                pass
            patient_id = getattr(self, '_current_patient_id', None)
            if not patient_id:
                QMessageBox.information(self, 'Linked Documents', 'Please select a patient first.')
                return
            file_path, _ = QFileDialog.getOpenFileName(
                self,
                'Select Document to Link',
                self._patient_documents_folder(int(patient_id)),
                'Documents (*.pdf *.jpg *.jpeg *.png *.tif *.tiff *.doc *.docx *.xls *.xlsx);;All Files (*.*)'
            )
            if not file_path:
                return
            # Ask for description
            desc, ok = QInputDialog.getText(self, 'Document Description', 'Enter a description for this document:')
            if not ok:
                return
            desc = (desc or '').strip()
            # Copy into managed folder with unique name
            import uuid
            dest_folder = self._patient_documents_folder(int(patient_id))
            ext = os.path.splitext(file_path)[1]
            unique_name = f"{uuid.uuid4().hex}{ext}"
            dest_path = os.path.join(dest_folder, unique_name)
            try:
                shutil.copy2(file_path, dest_path)
            except Exception as e:
                QMessageBox.critical(self, 'Linked Documents', f'Failed to copy file: {e}')
                return
            # Insert record
            conn = sqlite3.connect(self.patient_database_file)
            cur = conn.cursor()
            cur.execute(
                "INSERT INTO patient_documents (patient_id, description, original_name, stored_path) VALUES (?, ?, ?, ?)",
                (int(patient_id), desc or None, os.path.basename(file_path), dest_path),
            )
            conn.commit()
            conn.close()
            # Refresh
            self.load_patient_documents(int(patient_id))
        except Exception as e:
            QMessageBox.critical(self, 'Linked Documents', f'Failed to add document: {e}')

    def open_selected_patient_document(self):
        try:
            table = getattr(self, 'patient_documents_table', None)
            if not table:
                return
            row = table.currentRow()
            if row is None or row < 0:
                QMessageBox.information(self, 'Linked Documents', 'Please select a row first.')
                return
            item = table.item(row, 0)
            if not item:
                return
            path = item.data(Qt.ItemDataRole.UserRole + 1)
            if not path or not os.path.exists(path):
                QMessageBox.warning(self, 'Linked Documents', 'The stored file was not found on disk.')
                return
            try:
                os.startfile(path)
            except Exception:
                # Fallback: show folder
                try:
                    os.startfile(os.path.dirname(path))
                except Exception:
                    pass
        except Exception as e:
            QMessageBox.critical(self, 'Linked Documents', f'Failed to open document: {e}')
    
    def unlink_selected_patient_document(self):
        """Remove document link without deleting the actual file."""
        try:
            patient_id = getattr(self, '_current_patient_id', None)
            if not patient_id:
                QMessageBox.information(self, 'Linked Documents', 'Please select a patient first.')
                return
            table = getattr(self, 'patient_documents_table', None)
            if not table:
                return
            row = table.currentRow()
            if row is None or row < 0:
                QMessageBox.information(self, 'Linked Documents', 'Please select a row to unlink.')
                return
            item = table.item(row, 0)
            if not item:
                return
            rec_id = item.data(Qt.ItemDataRole.UserRole)
            desc = item.text()
            
            if QMessageBox.question(
                self,
                'Confirm Unlink',
                f'Unlink "{desc}" from this patient?\n\nThe file will remain on disk but will no longer be associated with this patient.',
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.No,
            ) != QMessageBox.StandardButton.Yes:
                return
            
            # Delete only the DB record, keep the file
            conn = sqlite3.connect(self.patient_database_file)
            cur = conn.cursor()
            cur.execute("DELETE FROM patient_documents WHERE id = ?", (int(rec_id),))
            conn.commit()
            conn.close()
            
            # Refresh table
            self.load_patient_documents(int(patient_id))
            QMessageBox.information(self, 'Unlink Complete', 'Document link removed. File remains on disk.')
        except Exception as e:
            QMessageBox.critical(self, 'Linked Documents', f'Failed to unlink document: {e}')

    def delete_selected_patient_document(self):
        try:
            patient_id = getattr(self, '_current_patient_id', None)
            if not patient_id:
                QMessageBox.information(self, 'Linked Documents', 'Please select a patient first.')
                return
            table = getattr(self, 'patient_documents_table', None)
            if not table:
                return
            row = table.currentRow()
            if row is None or row < 0:
                QMessageBox.information(self, 'Linked Documents', 'Please select a row to delete.')
                return
            item = table.item(row, 0)
            if not item:
                return
            rec_id = item.data(Qt.ItemDataRole.UserRole)
            path = item.data(Qt.ItemDataRole.UserRole + 1)
            if QMessageBox.question(
                self,
                'Confirm Delete',
                'Delete the selected linked document? This will remove the record and the copied file.',
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.No,
            ) != QMessageBox.StandardButton.Yes:
                return
            # Delete DB record
            conn = sqlite3.connect(self.patient_database_file)
            cur = conn.cursor()
            cur.execute("DELETE FROM patient_documents WHERE id = ?", (int(rec_id),))
            conn.commit()
            conn.close()
            # Delete file
            try:
                if path and os.path.exists(path):
                    os.remove(path)
            except Exception:
                pass
            # Refresh
            self.load_patient_documents(int(patient_id))
        except Exception as e:
            QMessageBox.critical(self, 'Linked Documents', f'Failed to delete document: {e}')

