    def load_orders(self):
        """Load orders from database into the orders table - ONE ROW PER ITEM."""
        try:
            if not hasattr(self, 'orders_db_path'):
                return
                
            conn = sqlite3.connect(self.orders_db_path)
            cursor = conn.cursor()
            cursor.execute(
                """
                SELECT id, rx_date, order_date, patient_last_name, patient_first_name,
                       order_status, delivery_date, pickup_date, tracking_number, notes, refill_number,
                       COALESCE(billed, 0), COALESCE(paid, 0), paid_date, COALESCE(is_pickup, 0)
                FROM orders
                ORDER BY id DESC
                """
            )
            orders = cursor.fetchall()
            conn.close()
            
            # Clear existing table
            self.orders_table.setRowCount(0)
            
            # Add orders to table - ONE ROW PER ITEM
            self._orders_updating = True
            for order in orders:
                order_id, rx_date, order_date, last_name, first_name, status, delivery_date, pickup_date, tracking_number, notes, refill_no, is_billed, is_paid, paid_date, is_pickup = order
                
                # Format data for display
                try:
                    order_num = self.format_order_number(order_id)
                except Exception:
                    order_num = f"ORD-{str(order_id).zfill(3)}" + (f"-R{refill_no}" if (refill_no or 0) > 0 else "")
                patient_name = f"{last_name}, {first_name}" if last_name and first_name else "N/A"
                
                # Get ALL items for this order
                conn = sqlite3.connect(self.orders_db_path)
                cur2 = conn.cursor()
                cur2.execute(
                    """
                    SELECT 
                        COALESCE(hcpcs_code,''), 
                        COALESCE(description,''),
                        COALESCE(item_number,''),
                        COALESCE(qty,''),
                        COALESCE(refills,''),
                        COALESCE(day_supply,'')
                    FROM order_items 
                    WHERE order_id = ? 
                    ORDER BY id ASC
                    """,
                    (order_id,),
                )
                items = cur2.fetchall()
                conn.close()
                
                if not items:
                    items = [("", "No items", "", "", "", "")]
                
                # Status text with icon
                status_text = status or "Pending"
                if "Delivered" in status_text:
                    status_display = f"✅ {status_text}"
                elif "Shipped" in status_text:
                    status_display = f"🚚 {status_text}"
                elif "Processing" in status_text:
                    status_display = f"📦 {status_text}"
                elif "Ready" in status_text:
                    status_display = f"✔️ {status_text}"
                elif "Picked Up" in status_text:
                    status_display = f"📤 {status_text}"
                else:
                    status_display = f"⏳ {status_text}"
                
                # Pickup date display
                pickup_display = pickup_date or (delivery_date if (is_pickup or (status and 'Picked Up' in status)) else "")
                
                # ADD ONE ROW PER ITEM
                for idx, item in enumerate(items):
                    item_hcpcs, item_desc, item_number, qty, refills_val, days_val = item
                    
                    row = self.orders_table.rowCount()
                    self.orders_table.insertRow(row)
                    
                    # Show order info only on FIRST item row
                    order_display = order_num if idx == 0 else ""
                    patient_display = patient_name if idx == 0 else ""
                    order_date_display = (order_date or "") if idx == 0 else ""
                    delivery_display = (delivery_date or "") if idx == 0 else ""
                    pickup_date_display = pickup_display if idx == 0 else ""
                    tracking_display = (tracking_number or "") if idx == 0 else ""
                    notes_display = (notes or "") if idx == 0 else ""
                    paid_display = ("Yes" if (is_paid or 0) else "No") if idx == 0 else ""
                    paid_date_display = (paid_date if paid_date else "") if idx == 0 else ""
                    
                    # Item-specific data
                    self.orders_table.setItem(row, 0, QTableWidgetItem(order_display))
                    self.orders_table.setItem(row, 1, QTableWidgetItem(patient_display))
                    self.orders_table.setItem(row, 2, QTableWidgetItem(item_hcpcs or ""))
                    self.orders_table.setItem(row, 3, QTableWidgetItem(item_number or ""))
                    self.orders_table.setItem(row, 4, QTableWidgetItem(item_desc or ""))
                    self.orders_table.setItem(row, 5, QTableWidgetItem(str(qty) if qty else ""))
                    self.orders_table.setItem(row, 6, QTableWidgetItem(str(refills_val) if refills_val else ""))
                    self.orders_table.setItem(row, 7, QTableWidgetItem(str(days_val) if days_val else ""))

                    # Calculate Refill Due Date for this item
                    due_item = QTableWidgetItem("")
                    try:
                        if days_val and (order_date or rx_date):
                            from datetime import datetime, timedelta
                            base_str = order_date or rx_date
                            base_date = None
                            for fmt in ("%Y-%m-%d", "%Y/%m/%d", "%m/%d/%Y", "%m-%d-%Y", "%Y-%m-%d %H:%M:%S", "%Y/%m/%d %H:%M:%S"):
                                try:
                                    base_date = datetime.strptime(str(base_str).split(" ")[0], fmt)
                                    break
                                except Exception:
                                    continue
                            if base_date:
                                due_dt = base_date + timedelta(days=int(float(days_val)))
                                due_str_iso = due_dt.strftime("%Y-%m-%d")
                                try:
                                    due_item.setText(self.format_date_display(due_str_iso))
                                except Exception:
                                    due_item.setText(due_str_iso)

                                # Apply row tint and emphasis
                                try:
                                    from datetime import timedelta as _td
                                    today = datetime.now().date()
                                    due_date = due_dt.date()
                                except Exception:
                                    due_date = None

                                if due_date is not None:
                                    if today >= due_date:
                                        # Due or overdue: bright green and bold in cell
                                        tint = QColor(40, 167, 69, 110)
                                        font = due_item.font()
                                        font.setBold(True)
                                        due_item.setFont(font)
                                    elif today >= (due_date - _td(days=5)):
                                        # Within 5-day window: soft green and bold due cell
                                        tint = QColor(40, 167, 69, 60)
                                        font = due_item.font()
                                        font.setBold(True)
                                        due_item.setFont(font)
                                    else:
                                        # Not due yet (outside window): red
                                        tint = QColor(220, 53, 69, 60)

                                    # Set the background tint for the entire row (light alpha)
                                    for c in range(self.orders_table.columnCount()):
                                        cell = self.orders_table.item(row, c)
                                        if cell is None:
                                            cell = QTableWidgetItem("")
                                            self.orders_table.setItem(row, c, cell)
                                        cell.setBackground(tint)
                    except Exception:
                        pass

                    self.orders_table.setItem(row, 8, due_item)  # Refill Due Date
                    self.orders_table.setItem(row, 9, QTableWidgetItem(order_date_display))
                    self.orders_table.setItem(row, 10, QTableWidgetItem(delivery_display))
                    self.orders_table.setItem(row, 11, QTableWidgetItem(pickup_date_display))
                    
                    # Status - show only on first row
                    if idx == 0:
                        status_item = QTableWidgetItem(status_display)
                        # Color code status
                        if "Delivered" in status_text or "Picked Up" in status_text:
                            status_item.setBackground(QColor("#28a745"))
                        elif "Shipped" in status_text:
                            status_item.setBackground(QColor("#ffc107"))
                        elif "Processing" in status_text or "Ready" in status_text:
                            status_item.setBackground(QColor("#17a2b8"))
                        else:
                            status_item.setBackground(QColor("#6c757d"))
                        self.orders_table.setItem(row, 12, status_item)
                    else:
                        self.orders_table.setItem(row, 12, QTableWidgetItem(""))
                    
                    self.orders_table.setItem(row, 13, QTableWidgetItem(tracking_display))
                    self.orders_table.setItem(row, 14, QTableWidgetItem(notes_display))

                    # Paid status - show only on first row
                    if idx == 0:
                        paid_item = QTableWidgetItem(paid_display)
                        paid_item.setTextAlignment(Qt.AlignmentFlag.AlignCenter)
                        self.orders_table.setItem(row, 15, paid_item)
                        
                        # Paid Date
                        paid_date_item = QTableWidgetItem(paid_date_display)
                        if is_paid and paid_date:
                            paid_date_item.setBackground(QColor("#d6eaf8"))  # Light blue
                        self.orders_table.setItem(row, 16, paid_date_item)
                    else:
                        self.orders_table.setItem(row, 15, QTableWidgetItem(""))
                        self.orders_table.setItem(row, 16, QTableWidgetItem(""))
            
            # Set column widths
            header = self.orders_table.horizontalHeader()
            header.resizeSection(2, 180)  # HCPCS Code (widened)
            self.orders_table.resizeColumnsToContents()
            print(f"✅ Loaded {len(orders)} orders (expanded to item rows)")
            self._orders_updating = False
            
        except Exception as e:
            print(f"Error loading orders: {e}")
    
    def apply_table_filters(self):
        """Apply filters to the orders table based on filter inputs."""
        order_filter = self.filter_order.text().lower()
        patient_filter = self.filter_patient.text().lower()
        hcpcs_filter = self.filter_hcpcs.text().lower()
        status_filter = self.filter_status.currentText()
        paid_filter = self.filter_paid.currentText()
        from_date = None
        to_date = None
        try:
            # Special value means no filter
            if self.filter_from_date.date() != self.filter_from_date.minimumDate():
                from_date = self.filter_from_date.date()
            if self.filter_to_date.date() != self.filter_to_date.minimumDate():
                to_date = self.filter_to_date.date()
        except Exception:
            pass
        
        for row in range(self.orders_table.rowCount()):
            show_row = True
            
            # Filter by Order #
            if order_filter and order_filter not in self.orders_table.item(row, 0).text().lower():
                show_row = False
            
            # Filter by Patient
            if patient_filter and patient_filter not in self.orders_table.item(row, 1).text().lower():
                show_row = False
            
            # Filter by HCPCS
            if hcpcs_filter and hcpcs_filter not in self.orders_table.item(row, 2).text().lower():
                show_row = False
            
            # Filter by Status (column 12)
            if status_filter != "All Status":
                status_item = self.orders_table.item(row, 12)
                status_text = status_item.text() if status_item else ""
                if status_filter not in status_text:
                    show_row = False
            
            # Filter by Paid (Yes/No text, column 15)
            if paid_filter != "All":
                paid_item = self.orders_table.item(row, 15)
                paid_text = (paid_item.text() if paid_item else "").strip().lower()
                is_paid = paid_text == "yes"
                if paid_filter == "Paid" and not is_paid:
                    show_row = False
                elif paid_filter == "Unpaid" and is_paid:
                    show_row = False

            # Filter by Order Date range
            if show_row and (from_date or to_date):
                date_item = self.orders_table.item(row, 9)  # Column 9 is Order Date, not column 7
                date_str = date_item.text() if date_item else ""
                if date_str:
                    d = QDate.fromString(date_str, "yyyy-MM-dd")
                    if not d.isValid():
                        # try alternate formats used elsewhere
                        d = QDate.fromString(date_str, "MM/dd/yyyy")
                else:
                    d = QDate()  # invalid
                if (from_date and (not d.isValid() or d < from_date)) or (to_date and (not d.isValid() or d > to_date)):
                    show_row = False
            
            self.orders_table.setRowHidden(row, not show_row)
    
    def clear_table_filters(self):
        """Clear all table filters."""
        self.filter_order.clear()
        self.filter_patient.clear()
        self.filter_hcpcs.clear()
        self.filter_rx.clear()  # Clear RX# filter too
        self.filter_status.setCurrentIndex(0)
        self.filter_paid.setCurrentIndex(0)
        try:
            # Reset date range to Any
            if hasattr(self, 'filter_from_date'):
                self.filter_from_date.setDate(self.filter_from_date.minimumDate())
            if hasattr(self, 'filter_to_date'):
                self.filter_to_date.setDate(self.filter_to_date.minimumDate())
        except Exception:
            pass
    
    def search_orders_by_rx(self):
        """Filter orders table by RX number from order_items."""
        rx_search = self.filter_rx.text().strip()
        
        if not rx_search:
            # If empty, show all rows (or let other filters apply)
            for row in range(self.orders_table.rowCount()):
                # Only unhide if not hidden by other filters
                # Re-apply other filters
                self.apply_table_filters()
            return
        
        try:
            if not hasattr(self, 'orders_db_path'):
                return
            
            # Find all order_ids that have items with matching RX numbers
            conn = sqlite3.connect(self.orders_db_path)
            cursor = conn.cursor()
            cursor.execute(
                """
                SELECT DISTINCT order_id 
                FROM order_items 
                WHERE LOWER(rx_number) LIKE ?
                """,
                (f'%{rx_search.lower()}%',)
            )
            matching_order_ids = {row[0] for row in cursor.fetchall()}
            conn.close()
            
            # Hide/show rows based on whether their order_id matches
            for row in range(self.orders_table.rowCount()):
                order_num_text = self.orders_table.item(row, 0).text() if self.orders_table.item(row, 0) else ""
                # Extract order ID from "ORD-123" or "ORD-123-R1" format
                try:
                    # Remove "ORD-" prefix and any refill suffix
                    order_id_str = order_num_text.replace("ORD-", "").split("-")[0]
                    order_id = int(order_id_str)
                    
                    # Show if this order has a matching RX item
                    show_row = order_id in matching_order_ids
                    self.orders_table.setRowHidden(row, not show_row)
                except Exception:
                    # If parsing fails, hide the row
                    self.orders_table.setRowHidden(row, True)
                    
        except Exception as e:
            print(f"Error searching orders by RX#: {e}")
        
        # Show all rows
        for row in range(self.orders_table.rowCount()):
            self.orders_table.setRowHidden(row, False)

