    def generate_refill_list(self):
        """Generate list of orders due for refills within the date range"""
        try:
            from_date = self.refill_from_date.date().toPyDate()
            to_date = self.refill_to_date.date().toPyDate()
            
            if from_date > to_date:
                QMessageBox.warning(self, "Invalid Date Range", "From date must be before To date.")
                return
            
            # Clear existing table
            self.refills_table.setRowCount(0)
            self.refills_table.setSortingEnabled(False)
            
            # Connect to orders database
            conn = sqlite3.connect(self.orders_database_file)
            cursor = conn.cursor()
            
            # Get all orders with items that have refills
            cursor.execute("""
                SELECT 
                    o.id,
                    o.order_date,
                    o.patient_last_name,
                    o.patient_first_name,
                    o.patient_dob,
                    o.patient_phone,
                    o.prescriber_name,
                    oi.hcpcs_code,
                    oi.description,
                    oi.refills,
                    oi.day_supply
                FROM orders o
                JOIN order_items oi ON o.id = oi.order_id
                WHERE oi.refills IS NOT NULL 
                  AND oi.refills != '' 
                  AND oi.refills != '0'
                  AND oi.day_supply IS NOT NULL 
                  AND oi.day_supply != ''
                ORDER BY o.order_date DESC
            """)
            
            orders = cursor.fetchall()
            conn.close()
            
            refill_count = 0
            
            for order in orders:
                order_id, order_date, last_name, first_name, dob, phone, prescriber, hcpcs, description, refills, day_supply = order
                patient_name = f"{first_name or ''} {last_name or ''}".strip()
                
                # Parse order date
                try:
                    order_dt = datetime.strptime(order_date, "%m/%d/%Y")
                except:
                    try:
                        order_dt = datetime.strptime(order_date, "%Y-%m-%d")
                    except:
                        continue
                
                # Parse refills and day supply
                try:
                    num_refills = int(refills)
                    num_days = int(day_supply)
                except:
                    continue
                
                # Skip if no refills remaining
                if num_refills <= 0 or num_days <= 0:
                    continue
                
                # Calculate next refill due date
                # Assuming the order date is when the first fill happened
                # Each refill is due after day_supply days
                next_refill_date = order_dt + timedelta(days=num_days)
                
                # Check if this refill falls within the selected date range
                if from_date <= next_refill_date.date() <= to_date:
                    # Calculate days until due
                    days_until = (next_refill_date.date() - QDate.currentDate().toPyDate()).days
                    
                    # Add row to table
                    row = self.refills_table.rowCount()
                    self.refills_table.insertRow(row)
                    
                    # Checkbox (column 0) - not editable
                    checkbox_item = QTableWidgetItem()
                    checkbox_item.setFlags(Qt.ItemFlag.ItemIsUserCheckable | Qt.ItemFlag.ItemIsEnabled)
                    checkbox_item.setCheckState(Qt.CheckState.Unchecked)
                    self.refills_table.setItem(row, 0, checkbox_item)

                    # Order ID (column 1) - not editable
                    order_id_item = QTableWidgetItem(str(order_id))
                    order_id_item.setFlags(order_id_item.flags() & ~Qt.ItemFlag.ItemIsEditable)
                    self.refills_table.setItem(row, 1, order_id_item)

                    # Editable columns (2+)
                    editable_columns = [
                        (2, QTableWidgetItem(order_date)),
                        (3, QTableWidgetItem(patient_name)),
                        (4, QTableWidgetItem(dob or "")),
                        (5, QTableWidgetItem(hcpcs or "")),
                        (6, QTableWidgetItem(description or "")),
                        (7, QTableWidgetItem(str(refills))),
                        (8, QTableWidgetItem(str(day_supply))),
                        (9, QTableWidgetItem(order_date)),
                    ]
                    for col, item in editable_columns:
                        item.setFlags(item.flags() | Qt.ItemFlag.ItemIsEditable | Qt.ItemFlag.ItemIsEnabled | Qt.ItemFlag.ItemIsSelectable)
                        self.refills_table.setItem(row, col, item)

                    # Next Refill Due (column 10) - editable, preserves color (Traffic Light Pattern)
                    next_due_str = next_refill_date.strftime("%m/%d/%Y")
                    due_item = QTableWidgetItem(next_due_str)
                    due_item.setFlags(due_item.flags() | Qt.ItemFlag.ItemIsEditable | Qt.ItemFlag.ItemIsEnabled | Qt.ItemFlag.ItemIsSelectable)
                    # Color code based on urgency (Traffic Light: Red=not due, Yellow=soon, Green=due/overdue)
                    if days_until <= 0:
                        due_item.setBackground(QColor("#28a745"))  # Green - due or overdue
                        due_item.setForeground(QColor("white"))
                    elif days_until <= 5:
                        due_item.setBackground(QColor("#ffc107"))  # Yellow - due within 5 days
                        due_item.setForeground(QColor("black"))
                    else:
                        due_item.setBackground(QColor("#dc3545"))  # Red - not due yet
                        due_item.setForeground(QColor("white"))
                    self.refills_table.setItem(row, 10, due_item)

                    # Days Until Due (column 11) - editable
                    days_item = QTableWidgetItem(str(days_until))
                    days_item.setTextAlignment(Qt.AlignmentFlag.AlignCenter)
                    days_item.setForeground(QColor("white"))
                    days_item.setFlags(days_item.flags() | Qt.ItemFlag.ItemIsEditable | Qt.ItemFlag.ItemIsEnabled | Qt.ItemFlag.ItemIsSelectable)
                    if days_until < 0:
                        days_item.setForeground(QColor("#e74c3c"))
                        days_item.setText(f"{days_until} (OVERDUE)")
                    self.refills_table.setItem(row, 11, days_item)

                    # Prescriber (column 12) - editable
                    prescriber_item = QTableWidgetItem(prescriber or "")
                    prescriber_item.setFlags(prescriber_item.flags() | Qt.ItemFlag.ItemIsEditable | Qt.ItemFlag.ItemIsEnabled | Qt.ItemFlag.ItemIsSelectable)
                    self.refills_table.setItem(row, 12, prescriber_item)

                    # Phone (column 13) - editable
                    phone_item = QTableWidgetItem(phone or "")
                    phone_item.setFlags(phone_item.flags() | Qt.ItemFlag.ItemIsEditable | Qt.ItemFlag.ItemIsEnabled | Qt.ItemFlag.ItemIsSelectable)
                    self.refills_table.setItem(row, 13, phone_item)
                    
                    # Days Until Due (column 11)
                    days_item = QTableWidgetItem(str(days_until))
                    days_item.setTextAlignment(Qt.AlignmentFlag.AlignCenter)
                    # default to white text for dark theme
                    days_item.setForeground(QColor("white"))
                    if days_until < 0:
                        days_item.setForeground(QColor("#e74c3c"))
                        days_item.setText(f"{days_until} (OVERDUE)")
                    self.refills_table.setItem(row, 11, days_item)
                    
                    # Prescriber (column 12)
                    self.refills_table.setItem(row, 12, QTableWidgetItem(prescriber or ""))
                    
                    # Phone (column 13)
                    self.refills_table.setItem(row, 13, QTableWidgetItem(phone or ""))
                    
                    refill_count += 1
            
            # Re-enable sorting
            self.refills_table.setSortingEnabled(True)
            
            # Update summary
            self.refills_summary_label.setText(
                f"Found {refill_count} refill(s) due between {from_date.strftime('%m/%d/%Y')} and {to_date.strftime('%m/%d/%Y')}"
            )
            self.refills_summary_label.setStyleSheet("color: #27ae60; font-weight: bold; padding: 5px;")
            
            if refill_count == 0:
                QMessageBox.information(self, "No Refills Due", 
                                      f"No refills are due between {from_date.strftime('%m/%d/%Y')} and {to_date.strftime('%m/%d/%Y')}.")
        
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to generate refill list:\n{e}")
            print(f"Error generating refill list: {e}")

    def clear_refill_list(self):
        """Clear the refills table"""
        self.refills_table.setRowCount(0)
        self.refills_summary_label.setText("Click 'Generate Refill List' to see orders due for refills.")
        self.refills_summary_label.setStyleSheet("color: #7f8c8d; font-style: italic; padding: 5px;")

    def export_refills_pdf(self):
        """Export refills list to PDF"""
        try:
            if self.refills_table.rowCount() == 0:
                QMessageBox.warning(self, "No Data", "Please generate a refill list first.")
                return
            
            from reportlab.lib.pagesizes import letter, landscape
            from reportlab.lib import colors
            from reportlab.lib.units import inch
            from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer
            from reportlab.lib.styles import getSampleStyleSheet
            
            # Get save location
            file_path, _ = QFileDialog.getSaveFileName(
                self, "Save Refills Report", 
                f"Refills_Report_{datetime.now().strftime('%Y%m%d_%H%M%S')}.pdf",
                "PDF Files (*.pdf)"
            )
            
            if not file_path:
                return
            
            # Create PDF
            doc = SimpleDocTemplate(file_path, pagesize=landscape(letter))
            elements = []
            styles = getSampleStyleSheet()
            
            # Title
            title = Paragraph(f"<b>Refills Due Report</b>", styles['Title'])
            elements.append(title)
            elements.append(Spacer(1, 0.2*inch))
            
            # Date range
            from_date = self.refill_from_date.date().toString("MM/dd/yyyy")
            to_date = self.refill_to_date.date().toString("MM/dd/yyyy")
            date_para = Paragraph(f"Date Range: {from_date} to {to_date}", styles['Normal'])
            elements.append(date_para)
            elements.append(Spacer(1, 0.3*inch))
            
            # Prepare table data
            data = [["Order", "Patient", "HCPCS", "Refills", "Days", "Next Due", "Days Until", "Prescriber"]]
            
            for row in range(self.refills_table.rowCount()):
                row_data = [
                    self.refills_table.item(row, 1).text(),  # Order ID
                    self.refills_table.item(row, 3).text(),  # Patient
                    self.refills_table.item(row, 5).text(),  # HCPCS
                    self.refills_table.item(row, 7).text(),  # Refills
                    self.refills_table.item(row, 8).text(),  # Day Supply
                    self.refills_table.item(row, 10).text(),  # Next Due
                    self.refills_table.item(row, 11).text(), # Days Until
                    self.refills_table.item(row, 12).text()  # Prescriber
                ]
                data.append(row_data)
            
            # Create table
            table = Table(data)
            table.setStyle(TableStyle([
                ('BACKGROUND', (0, 0), (-1, 0), colors.grey),
                ('TEXTCOLOR', (0, 0), (-1, 0), colors.whitesmoke),
                ('ALIGN', (0, 0), (-1, -1), 'LEFT'),
                ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
                ('FONTSIZE', (0, 0), (-1, 0), 10),
                ('BOTTOMPADDING', (0, 0), (-1, 0), 12),
                ('BACKGROUND', (0, 1), (-1, -1), colors.beige),
                ('GRID', (0, 0), (-1, -1), 1, colors.black),
                ('FONTSIZE', (0, 1), (-1, -1), 8),
            ]))
            
            elements.append(table)
            
            # Build PDF
            doc.build(elements)
            
            QMessageBox.information(self, "Export Complete", f"Refills report exported to:\n{file_path}")
            
        except Exception as e:
            QMessageBox.critical(self, "Export Error", f"Failed to export PDF:\n{e}")

    def toggle_all_refills(self, state):
        """Toggle all checkboxes in the refills table"""
        check_state = Qt.CheckState.Checked if state == Qt.CheckState.Checked.value else Qt.CheckState.Unchecked
        
        for row in range(self.refills_table.rowCount()):
            checkbox_item = self.refills_table.item(row, 0)
            if checkbox_item:
                checkbox_item.setCheckState(check_state)

    def handle_refill_double_click(self, row, column):
        """Handle double-click on a refill row to create refill order"""
        if row < 0 or row >= self.refills_table.rowCount():
            return
        
        try:
            # Get the original order ID
            order_id_item = self.refills_table.item(row, 1)
            if not order_id_item:
                return
            
            order_id = int(order_id_item.text())
            
            # Confirm with user
            patient_name = self.refills_table.item(row, 3).text()
            reply = QMessageBox.question(
                self,
                "Create Refill Order",
                f"Create refill order for:\n{patient_name}\n\nOriginal Order ID: {order_id}",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.Yes
            )
            
            if reply == QMessageBox.StandardButton.Yes:
                success = self.create_single_refill_order(order_id)
                if success:
                    # Remove row from table after successful creation
                    self.refills_table.removeRow(row)
                    QMessageBox.information(self, "Success", f"Refill order created for {patient_name}")
        
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to create refill order:\n{e}")
            print(f"Error in handle_refill_double_click: {e}")

    def create_batch_refill_orders(self):
        """Create refill orders for all checked items in the table"""
        try:
            # Find all checked rows
            checked_rows = []
            for row in range(self.refills_table.rowCount()):
                checkbox_item = self.refills_table.item(row, 0)
                if checkbox_item and checkbox_item.checkState() == Qt.CheckState.Checked:
                    order_id_item = self.refills_table.item(row, 1)
                    patient_name_item = self.refills_table.item(row, 3)
                    if order_id_item and patient_name_item:
                        checked_rows.append({
                            'row': row,
                            'order_id': int(order_id_item.text()),
                            'patient_name': patient_name_item.text()
                        })
            
            if not checked_rows:
                QMessageBox.warning(self, "No Selection", "Please select at least one order by checking the checkbox.")
                return
            
            # Confirm batch creation
            reply = QMessageBox.question(
                self,
                "Create Batch Refill Orders",
                f"Create refill orders for {len(checked_rows)} selected patient(s)?",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.Yes
            )
            
            if reply != QMessageBox.StandardButton.Yes:
                return
            
            # Create progress dialog
            progress = QProgressDialog("Creating refill orders...", "Cancel", 0, len(checked_rows), self)
            progress.setWindowTitle("Batch Processing")
            progress.setWindowModality(Qt.WindowModality.WindowModal)
            progress.show()
            
            success_count = 0
            failed_orders = []
            
            # Process each checked order (in reverse to avoid row index issues)
            for i, order_data in enumerate(reversed(checked_rows)):
                if progress.wasCanceled():
                    break
                
                progress.setValue(i)
                progress.setLabelText(f"Creating refill for {order_data['patient_name']}...")
                QApplication.processEvents()
                
                try:
                    if self.create_single_refill_order(order_data['order_id']):
                        success_count += 1
                        # Remove row from table
                        self.refills_table.removeRow(order_data['row'])
                    else:
                        failed_orders.append(order_data['patient_name'])
                except Exception as e:
                    failed_orders.append(f"{order_data['patient_name']} ({str(e)})")
            
            progress.setValue(len(checked_rows))
            progress.close()
            
            # Show results
            result_msg = f"✅ Successfully created {success_count} refill order(s)."
            if failed_orders:
                result_msg += f"\n\n❌ Failed ({len(failed_orders)}):\n" + "\n".join(failed_orders[:10])
                if len(failed_orders) > 10:
                    result_msg += f"\n... and {len(failed_orders) - 10} more"
            
            QMessageBox.information(self, "Batch Processing Complete", result_msg)
            
            # Update summary
            remaining = self.refills_table.rowCount()
            if remaining == 0:
                self.refills_summary_label.setText("All refills processed! Click 'Generate Refill List' to refresh.")
            else:
                self.refills_summary_label.setText(f"{remaining} refill(s) remaining in list.")
        
        except Exception as e:
            QMessageBox.critical(self, "Batch Error", f"Failed to process batch refill orders:\n{e}")
            print(f"Error in create_batch_refill_orders: {e}")

    def create_single_refill_order(self, original_order_id):
        """Create a new refill order based on an existing order"""
        try:
            # Connect to database
            conn = sqlite3.connect(self.orders_database_file)
            cursor = conn.cursor()
            
            # Get the original order
            cursor.execute("""
                SELECT 
                    rx_date, order_date, patient_last_name, patient_first_name, patient_dob,
                    patient_address, patient_phone, patient_secondary_contact,
                    icd_code_1, icd_code_2, icd_code_3, icd_code_4, icd_code_5,
                    prescriber_name, prescriber_npi, primary_insurance, primary_insurance_id,
                    secondary_insurance, secondary_insurance_id, billing_selection, order_status
                FROM orders WHERE id = ?
            """, (original_order_id,))
            
            original_order = cursor.fetchone()
            
            if not original_order:
                conn.close()
                QMessageBox.warning(self, "Order Not Found", f"Original order ID {original_order_id} not found.")
                return False
            
            # Create new order with today's date as order date
            today = datetime.now().strftime("%m/%d/%Y")
            
            cursor.execute("""
                INSERT INTO orders (
                    rx_date, order_date, patient_last_name, patient_first_name, patient_dob,
                    patient_address, patient_phone, patient_secondary_contact,
                    icd_code_1, icd_code_2, icd_code_3, icd_code_4, icd_code_5,
                    prescriber_name, prescriber_npi, primary_insurance, primary_insurance_id,
                    secondary_insurance, secondary_insurance_id, billing_selection, order_status,
                    parent_order_id, refill_number
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """, (
                original_order[0],  # rx_date (keep original)
                today,              # order_date (today)
                original_order[2],  # patient_last_name
                original_order[3],  # patient_first_name
                original_order[4],  # patient_dob
                original_order[5],  # patient_address
                original_order[6],  # patient_phone
                original_order[7],  # patient_secondary_contact
                original_order[8],  # icd_code_1
                original_order[9],  # icd_code_2
                original_order[10], # icd_code_3
                original_order[11], # icd_code_4
                original_order[12], # icd_code_5
                original_order[13], # prescriber_name
                original_order[14], # prescriber_npi
                original_order[15], # primary_insurance
                original_order[16], # primary_insurance_id
                original_order[17], # secondary_insurance
                original_order[18], # secondary_insurance_id
                original_order[19], # billing_selection
                "Pending",          # order_status
                original_order_id,  # parent_order_id
                1                   # refill_number (first refill)
            ))
            
            new_order_id = cursor.lastrowid
            
            # Copy order items from original order
            cursor.execute("""
                SELECT rx_no, hcpcs_code, description, refills, day_supply, qty, cost_ea, total, pa_number
                FROM order_items WHERE order_id = ?
            """, (original_order_id,))
            
            original_items = cursor.fetchall()
            
            for item in original_items:
                # Decrease refill count by 1
                original_refills = int(item[3]) if item[3] and item[3].isdigit() else 0
                new_refills = max(0, original_refills - 1)
                
                cursor.execute("""
                    INSERT INTO order_items (
                        order_id, rx_no, hcpcs_code, description, refills, day_supply, qty, cost_ea, total, pa_number
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """, (
                    new_order_id,
                    item[0],  # rx_no
                    item[1],  # hcpcs_code
                    item[2],  # description
                    str(new_refills),  # refills (decremented)
                    item[4],  # day_supply
                    item[5],  # qty
                    item[6],  # cost_ea
                    item[7],  # total
                    item[8]   # pa_number
                ))
            
            conn.commit()
            conn.close()
            
            # Refresh orders table if visible
            if hasattr(self, 'orders_table'):
                self.load_orders()
            
            return True
        
        except Exception as e:
            print(f"Error creating refill order: {e}")
            if 'conn' in locals():
                conn.close()
            return False

    def open_billing_report_from_billing_tab(self):
        """Switch to Reports tab and generate Billing report for the current date range."""
        try:
            # Ensure reports tab exists and is selected
            if hasattr(self, 'reports_tab'):
                idx = self.main_tabs.indexOf(self.reports_tab)
                if idx != -1:
                    self.main_tabs.setCurrentIndex(idx)
            # Generate the billing report
            self.generate_billing_report()
        except Exception as e:
            QMessageBox.warning(self, "Billing Report", f"Unable to open Billing Report: {e}")

    def convert_to_uppercase(self, field, text):
        """Convert field text to uppercase automatically"""
        if text != text.upper():
            # Block signals to prevent infinite loop
            field.blockSignals(True)
            # Get cursor position
            cursor_pos = field.cursorPosition()
            # Set uppercase text
            field.setText(text.upper())
            # Restore cursor position
            field.setCursorPosition(cursor_pos)
            # Unblock signals
            field.blockSignals(False)

    def load_settings(self):
        """Load settings from JSON file. Does NOT create defaults - First-Run Wizard handles that."""
        try:
            if os.path.exists(SETTINGS_FILE):
                with open(SETTINGS_FILE, 'r') as f:
                    settings = json.load(f)
                    if 'quick_folders' not in settings:
                        settings['quick_folders'] = []
                    return settings
        except Exception as e:
            print(f"Error loading settings: {e}")
        
        # Return minimal defaults - do NOT create db_folder (First-Run Wizard handles that)
        return {
            "last_folder": DEFAULT_FOLDER_PATH,
            "quick_folders": []
        }

    def save_settings(self):
        """Save settings to JSON file."""
        try:
            with open(SETTINGS_FILE, 'w') as f:
                json.dump(self.settings, f, indent=2)
        except Exception as e:
            print(f"Error saving settings: {e}")

    def populate_folder_combo(self):
        """Populate the quick folder combo box."""
        self.folder_combo.clear()
        self.folder_combo.addItem("Select quick folder...")
        
        quick_folders = self.settings.get('quick_folders', [])
        for folder in quick_folders:
            if os.path.exists(folder):
                folder_name = os.path.basename(folder) or folder
                self.folder_combo.addItem(f"📁 {folder_name}", folder)

    def on_quick_folder_changed(self):
        """Handle quick folder selection."""
        current_data = self.folder_combo.currentData()
        if current_data and current_data != self.folder_path:
            self.switch_to_folder(current_data)

    def save_current_folder(self):
        """Save current folder to quick folders."""
        if not self.folder_path:
            return
            
        quick_folders = self.settings.get('quick_folders', [])
        
        if self.folder_path not in quick_folders:
            quick_folders.append(self.folder_path)
            if len(quick_folders) > 5:
                quick_folders.pop(0)
            
            self.settings['quick_folders'] = quick_folders
            self.save_settings()
            self.populate_folder_combo()
            
            QMessageBox.information(self, "Folder Saved", 
                                  f"Current folder saved to quick access:\n{os.path.basename(self.folder_path)}")
        else:
            QMessageBox.information(self, "Already Saved", 
                                  "This folder is already in quick access.")

    def remove_selected_folder(self):
        """Remove selected folder from quick folders."""
        current_data = self.folder_combo.currentData()
        if current_data:
            quick_folders = self.settings.get('quick_folders', [])
            if current_data in quick_folders:
                quick_folders.remove(current_data)
                self.settings['quick_folders'] = quick_folders
                self.save_settings()
                self.populate_folder_combo()
                
                QMessageBox.information(self, "Folder Removed", 
                                      f"Removed from quick access:\n{os.path.basename(current_data)}")

    def switch_to_folder(self, folder_path):
        """Switch to a different folder."""
        if not os.path.exists(folder_path):
            QMessageBox.warning(self, "Folder Not Found", 
                              f"The folder no longer exists:\n{folder_path}")
            return
        
        if self.current_file:
            self.save_data(self.current_file)
            print(f"Auto-saved before folder switch: {self.current_file}")
        
        self.folder_path = folder_path
        self.database_file = os.path.join(self.folder_path, "document_data.db")
        
        self.settings['last_folder'] = self.folder_path
        self.save_settings()
        
        self.folder_label.setText(f"Current: {os.path.basename(self.folder_path)}")
        self.setWindowTitle(f"Document Manager v1.0 - {os.path.basename(self.folder_path)}")
        
        self.reset_viewer_and_fields()
        self.setup_database()
        self.load_file_list()
        
        self.statusBar().showMessage(f"Switched to folder: {os.path.basename(self.folder_path)}")

    def scroll_wheel_event(self, event):
        """Handle mouse wheel scrolling with Ctrl+wheel for zooming."""
        modifiers = QApplication.keyboardModifiers()
        
        if modifiers == Qt.KeyboardModifier.ControlModifier:
            if event.angleDelta().y() > 0:
                self.zoom_in()
            else:
                self.zoom_out()
        else:
            QScrollArea.wheelEvent(self.scroll_area, event)

