    def toggle_theme(self):
        """Quickly toggle between Dark and Light themes and persist the setting."""
        try:
            current = self.settings.get('theme', 'Dark')
            new_theme = 'Light' if current != 'Light' else 'Dark'
            self.apply_settings({'theme': new_theme})
        except Exception:
            # Fallback: directly call theme apply
            if getattr(self, 'is_dark_theme', True):
                self.apply_light_theme()
            else:
                self.apply_dark_theme()

    def build_ocr_index(self):
        """Build OCR index for all PDF files in background."""
        reply = QMessageBox.question(self, "Build OCR Index", 
                                   "This will process all PDF files and build a searchable index.\n\nThis may take several minutes depending on the number of files.\n\nContinue?", 
                                   QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No)
        
        if reply == QMessageBox.StandardButton.Yes:
            # Start OCR indexing in background using our existing OCR indexer
            try:
                pdf_files = [f for f in os.listdir(self.folder_path) if f.lower().endswith('.pdf')]
                
                if not pdf_files:
                    QMessageBox.information(self, "No Files", "No PDF files found to index.")
                    return
                    
                # Update status
                if hasattr(self, 'search_status_label'):
                    self.search_status_label.setText(f"Starting OCR indexing of {len(pdf_files)} files...")
                
                # Use our OCR indexer to process files
                for i, filename in enumerate(pdf_files):
                    file_path = os.path.join(self.folder_path, filename)
                    if hasattr(self, 'search_status_label'):
                        self.search_status_label.setText(f"Indexing {i+1}/{len(pdf_files)}: {filename}")
                    
                    # Process with OCR indexer
                    try:
                        # Extract text from PDF using OCR
                        from ocr_tools import extract_text_from_pdf, get_last_modified
                        text = extract_text_from_pdf(file_path)
                        last_modified = get_last_modified(file_path)
                        
                        # Add to index
                        self.ocr_indexer.add_or_update(file_path, text, last_modified)
                        
                    except Exception as e:
                        print(f"Failed to process {filename}: {e}")
                        if hasattr(self, 'search_status_label'):
                            self.search_status_label.setText(f"Error processing {filename}: {e}")
                    
                    # Process events to keep UI responsive
                    QApplication.processEvents()
                
                if hasattr(self, 'search_status_label'):
                    self.search_status_label.setText(f"OCR indexing complete! {len(pdf_files)} files processed.")
                    
                QMessageBox.information(self, "Indexing Complete", 
                                       f"Successfully indexed {len(pdf_files)} PDF files.\n\nYou can now search through document content instantly!")
                    
            except Exception as e:
                QMessageBox.critical(self, "Indexing Error", f"Failed to build OCR index:\n\n{str(e)}")
                if hasattr(self, 'search_status_label'):
                    self.search_status_label.setText("OCR indexing failed.")

    # --- OCR folder watcher management (live updates) ---
    def start_ocr_folder_watcher(self):
        """Start watching the PDF folder to keep the OCR index up to date automatically."""
        try:
            from threading import Event, Thread
            from ocr_indexer import watch_folder

            # Prefer the network/main folder if present, else fall back to the local 'faxes' folder
            main_folder = r"C:\FaxManagerData\FaxManagerData\Faxes OCR'd"
            local_folder = "faxes"

            if os.path.exists(main_folder):
                watch_path = main_folder
            elif os.path.exists(local_folder):
                watch_path = local_folder
            else:
                print("⚠️ No PDF folder found for watching")
                return

            # Initialize and start background watcher
            self.ocr_stop_event = Event()
            self.ocr_watcher_thread = Thread(
                target=watch_folder,
                args=(watch_path, r"C:\FaxManagerData\FaxManagerData\ocr_cache.db", self.ocr_stop_event),
                daemon=True,
            )
            self.ocr_watcher_thread.start()
            print(f"👁️ OCR folder watcher started: {watch_path}")

        except Exception as e:
            print(f"❌ Failed to start OCR folder watcher: {e}")

    def stop_ocr_folder_watcher(self):
        """Stop the OCR folder watcher thread if running."""
        try:
            if getattr(self, 'ocr_stop_event', None) and getattr(self, 'ocr_watcher_thread', None):
                print("🛑 Stopping OCR folder watcher…")
                self.ocr_stop_event.set()
                try:
                    self.ocr_watcher_thread.join(timeout=2)
                except Exception:
                    pass
                print("✅ OCR folder watcher stopped")
        except Exception as e:
            print(f"⚠️ Error while stopping OCR folder watcher: {e}")
    
    def show_file_context_menu(self, position):
        """Show context menu for file operations: rename and move to subfolder."""
        item = self.file_list_widget.itemAt(position)
        if not item:
            return
        
        menu = QMenu(self)
        menu.setStyleSheet("""
            QMenu {
                background-color: #2B2B2B;
                color: white;
                border: 1px solid #424242;
            }
            QMenu::item:selected {
                background-color: #404040;
            }
        """)
        
        rename_action = menu.addAction("✏️ Rename File")
        move_action = menu.addAction("📁 Move to Subfolder")
        delete_action = menu.addAction("🗑 Delete File")
        
        action = menu.exec(self.file_list_widget.mapToGlobal(position))
        
        if action == rename_action:
            self.rename_file(item.text())
        elif action == move_action:
            self.move_file_to_subfolder(item.text())
        elif action == delete_action:
            self.delete_file(item.text())
    
    def rename_file(self, old_filename):
        """Rename the selected PDF file."""
        try:
            old_path = os.path.join(self.folder_path, old_filename)
            if not os.path.exists(old_path):
                QMessageBox.warning(self, "File Not Found", f"File '{old_filename}' does not exist.")
                return
            
            # Check if this is the currently loaded PDF
            is_current_file = False
            if hasattr(self, 'current_pdf_path') and self.current_pdf_path:
                current_filename = os.path.basename(self.current_pdf_path)
                is_current_file = (current_filename == old_filename)
            
            # Suggest a new name based on current patient/order data if available
            suggested_name = old_filename
            try:
                # Try to build a suggested name from patient fields if loaded
                if hasattr(self, 'patient_fields') and isinstance(self.patient_fields, dict):
                    last_name = self.patient_fields.get('last_name', None)
                    first_name = self.patient_fields.get('first_name', None)
                    dob = self.patient_fields.get('dob', None)
                    
                    if last_name and hasattr(last_name, 'text'):
                        last_name = last_name.text().strip().upper()
                    if first_name and hasattr(first_name, 'text'):
                        first_name = first_name.text().strip().upper()
                    if dob and hasattr(dob, 'text'):
                        dob = dob.text().strip()
                    
                    if last_name and first_name:
                        # Format: LAST, FIRST (DOB) items RX date.pdf
                        from datetime import datetime
                        date_str = datetime.now().strftime("%m-%d-%Y")
                        suggested_name = f"{last_name}, {first_name}"
                        if dob:
                            suggested_name += f" ({dob})"
                        suggested_name += f" RX {date_str}.pdf"
            except Exception as e:
                print(f"Could not build suggested name: {e}")
            
            # Prompt for new filename
            new_filename, ok = QInputDialog.getText(
                self,
                "Rename File",
                "Enter new filename:",
                text=suggested_name
            )
            
            if not ok or not new_filename.strip():
                return
            
            # Ensure .pdf extension
            new_filename = new_filename.strip()
            if not new_filename.lower().endswith('.pdf'):
                new_filename += '.pdf'
            
            new_path = os.path.join(self.folder_path, new_filename)
            
            if os.path.exists(new_path):
                QMessageBox.warning(self, "File Exists", f"A file named '{new_filename}' already exists.")
                return
            
            # If this is the current file, close it first
            if is_current_file:
                # Strategy: Switch to a different file to force PyMuPDF to release this one
                # Find another file in the list
                other_file = None
                for i in range(self.file_list_widget.count()):
                    item_text = self.file_list_widget.item(i).text()
                    if item_text != old_filename:
                        other_file = item_text
                        break
                
                if other_file:
                    # Select and load the other file - this will close the current one
                    for i in range(self.file_list_widget.count()):
                        if self.file_list_widget.item(i).text() == other_file:
                            self.file_list_widget.setCurrentRow(i)
                            break
                    # Give it a moment to load and close the old file
                    import time
                    time.sleep(0.2)
                else:
                    # No other file available, manually close
                    self.current_file = None
                    self.current_pdf_path = None
                    
                    try:
                        self.pdf_label.clear()
                        self.pdf_label.setText("PDF closed for renaming...")
                        self.pdf_label.setPixmap(QPixmap())
                    except Exception:
                        pass
                    
                    if hasattr(self, 'doc') and self.doc:
                        try:
                            self.doc.close()
                            self.doc = None
                        except Exception:
                            pass
                    
                    if hasattr(self, 'pdf_document') and self.pdf_document:
                        try:
                            self.pdf_document.close()
                            self.pdf_document = None
                        except Exception:
                            pass
                    
                    # Force garbage collection
                    import gc
                    gc.collect()
                    time.sleep(0.2)
            
            # Rename the file
            try:
                os.rename(old_path, new_path)
            except PermissionError:
                QMessageBox.critical(self, "Error", 
                    "Document not closed\n\n"
                    "The file is still in use. Please:\n"
                    "1. Select a different file in the list\n"
                    "2. Wait a moment\n"
                    "3. Try renaming again")
                return
            print(f"✅ Renamed: {old_filename} → {new_filename}")
            
            # Refresh file list and select the renamed file
            self.load_file_list()
            for i in range(self.file_list_widget.count()):
                if self.file_list_widget.item(i).text() == new_filename:
                    self.file_list_widget.setCurrentRow(i)
                    break
            
            QMessageBox.information(self, "Success", f"File renamed to:\n{new_filename}")
            
        except Exception as e:
            print(f"Error renaming file: {e}")
            QMessageBox.critical(self, "Error", f"Failed to rename file:\n{e}")
    
    def move_file_to_subfolder(self, filename):
        """Move the selected PDF file to a subfolder."""
        try:
            source_path = os.path.join(self.folder_path, filename)
            if not os.path.exists(source_path):
                QMessageBox.warning(self, "File Not Found", f"File '{filename}' does not exist.")
                return
            
            # Check if this is the currently loaded PDF
            is_current_file = False
            if hasattr(self, 'current_pdf_path') and self.current_pdf_path:
                current_filename = os.path.basename(self.current_pdf_path)
                is_current_file = (current_filename == filename)
            
            # Get list of existing subfolders
            subfolders = [f for f in os.listdir(self.folder_path) 
                         if os.path.isdir(os.path.join(self.folder_path, f))]
            subfolders.sort()
            
            # Prompt for subfolder (with autocomplete)
            subfolder, ok = QInputDialog.getItem(
                self,
                "Move to Subfolder",
                f"Select or type subfolder name for '{filename}':",
                subfolders,
                0,
                True  # Editable
            )
            
            if not ok or not subfolder.strip():
                return
            
            subfolder = subfolder.strip()
            
            # Create subfolder if it doesn't exist
            subfolder_path = os.path.join(self.folder_path, subfolder)
            if not os.path.exists(subfolder_path):
                os.makedirs(subfolder_path)
                print(f"✅ Created subfolder: {subfolder}")
            
            # Move the file
            dest_path = os.path.join(subfolder_path, filename)
            if os.path.exists(dest_path):
                reply = QMessageBox.question(
                    self,
                    "File Exists",
                    f"A file named '{filename}' already exists in '{subfolder}'.\nOverwrite?",
                    QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No
                )
                if reply != QMessageBox.StandardButton.Yes:
                    return
                os.remove(dest_path)
            
            # If this is the current file, close it first
            if is_current_file:
                # Strategy: Switch to a different file to force PyMuPDF to release this one
                # Find another file in the list
                other_file = None
                for i in range(self.file_list_widget.count()):
                    item_text = self.file_list_widget.item(i).text()
                    if item_text != filename:
                        other_file = item_text
                        break
                
                if other_file:
                    # Select and load the other file - this will close the current one
                    for i in range(self.file_list_widget.count()):
                        if self.file_list_widget.item(i).text() == other_file:
                            self.file_list_widget.setCurrentRow(i)
                            break
                    # Give it a moment to load and close the old file
                    import time
                    time.sleep(0.2)
                else:
                    # No other file available, manually close
                    self.current_file = None
                    self.current_pdf_path = None
                    
                    try:
                        self.pdf_label.clear()
                        self.pdf_label.setText("PDF closed for moving...")
                        self.pdf_label.setPixmap(QPixmap())
                    except Exception:
                        pass
                    
                    if hasattr(self, 'doc') and self.doc:
                        try:
                            self.doc.close()
                            self.doc = None
                        except Exception:
                            pass
                    
                    if hasattr(self, 'pdf_document') and self.pdf_document:
                        try:
                            self.pdf_document.close()
                            self.pdf_document = None
                        except Exception:
                            pass
                    
                    # Force garbage collection
                    import gc
                    gc.collect()
                    time.sleep(0.2)
            
            import shutil
            try:
                shutil.move(source_path, dest_path)
            except PermissionError:
                QMessageBox.critical(self, "Error", 
                    "Document not closed\n\n"
                    "The file is still in use. Please:\n"
                    "1. Select a different file in the list\n"
                    "2. Wait a moment\n"
                    "3. Try moving again")
                return
            print(f"✅ Moved: {filename} → {subfolder}/")
            
            # Refresh file list
            self.load_file_list()
            
            QMessageBox.information(self, "Success", f"File moved to:\n{subfolder}/{filename}")
            
        except Exception as e:
            print(f"Error moving file: {e}")
            QMessageBox.critical(self, "Error", f"Failed to move file:\n{e}")

    def delete_file(self, filename: str):
        """Safely delete a PDF from disk and refresh the UI."""
        try:
            path = os.path.join(self.folder_path, filename)
            if not os.path.exists(path):
                QMessageBox.warning(self, "Delete", f"File not found:\n{path}")
                return

            # Confirm
            reply = QMessageBox.question(
                self, "Confirm Delete",
                f"Are you sure you want to permanently delete:\n\n{filename}",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.No
            )
            if reply != QMessageBox.StandardButton.Yes:
                return

            # If this is the open document, close it cleanly
            is_current = False
            try:
                if hasattr(self, 'current_pdf_path') and self.current_pdf_path:
                    is_current = (os.path.basename(self.current_pdf_path) == filename)
            except Exception:
                pass

            if is_current:
                try:
                    # Clear viewer first so Windows can release the file handle
                    self.pdf_label.clear()
                    self.pdf_label.setText("PDF closed.")
                    self.pdf_label.setPixmap(QPixmap())
                except Exception:
                    pass
                try:
                    if getattr(self, 'doc', None):
                        self.doc.close()
                        self.doc = None
                except Exception:
                    pass
                try:
                    if getattr(self, 'pdf_document', None):
                        self.pdf_document.close()
                        self.pdf_document = None
                except Exception:
                    pass

            # Delete the file
            try:
                os.remove(path)
            except PermissionError:
                QMessageBox.critical(
                    self, "Delete",
                    "Document not closed.\n\nSelect a different file, wait a moment, then try again."
                )
                return

            # Refresh list and clear selection
            self.load_file_list()
            self.current_file = None
            self.current_pdf_path = None
            self.statusBar().showMessage(f"Deleted: {filename}", 3000)
            QMessageBox.information(self, "Deleted", f"The file was deleted:\n{filename}")

        except Exception as e:
            QMessageBox.critical(self, "Delete", f"Failed to delete file:\n{e}")

    def load_file_list(self):
        """Scan current folder and populate the left-hand PDF file list."""
        self.file_list_widget.clear()
        # Clear any search highlighting when file list is refreshed
        if hasattr(self, 'search_results_table') or hasattr(self, 'search_results_list'):
            self.clear_file_highlighting()

        # Clear filename cache when folder changes
        if hasattr(self, 'filename_cache'):
            self.filename_cache.clear()

        try:
            pdf_files = [f for f in os.listdir(self.folder_path) if f.lower().endswith('.pdf')]
            
            # Sort by date extracted from filename (format: PHONENUMBER-MMDD-HHMMSS-NNN.pdf)
            # Most recent first (reverse sort)
            def extract_date_from_filename(filename):
                try:
                    from datetime import datetime
                    # Split by hyphen and look for date pattern
                    parts = filename.replace('.pdf', '').split('-')
                    if len(parts) >= 3:
                        # Second part is MMDD (4 digits), third part is HHMMSS (6 digits)
                        date_str = parts[1]  # MMDD
                        time_str = parts[2]  # HHMMSS
                        
                        if len(date_str) == 4 and date_str.isdigit():
                            month = int(date_str[0:2])
                            day = int(date_str[2:4])
                            year = 2025  # Current year
                            
                            hour = 0
                            minute = 0
                            second = 0
                            if len(time_str) == 6 and time_str.isdigit():
                                hour = int(time_str[0:2])
                                minute = int(time_str[2:4])
                                second = int(time_str[4:6])
                            
                            return datetime(year, month, day, hour, minute, second)
                except Exception as e:
                    print(f"Date parse error for {filename}: {e}")
                # Fallback to file modification time if parsing fails
                try:
                    from datetime import datetime
                    return datetime.fromtimestamp(os.path.getmtime(os.path.join(self.folder_path, filename)))
                except Exception:
                    from datetime import datetime
                    return datetime(1970, 1, 1)
            
            # Sort with most recent first (reverse=True for descending order)
            pdf_files.sort(key=extract_date_from_filename, reverse=True)
            
            for filename in pdf_files:
                self.file_list_widget.addItem(filename)

            # Refresh filter dropdowns with new file data
            if hasattr(self, 'fax_filter_combo'):
                self.populate_fax_filter()

            # Update status
            count = len(pdf_files)
            try:
                self.statusBar().showMessage(f"Found {count} PDF file{'s' if count != 1 else ''} in {os.path.basename(self.folder_path)}")
            except Exception:
                pass

        except FileNotFoundError:
            self.pdf_label.setText(f"Error: Folder not found.\n{self.folder_path}")
            try:
                self.statusBar().showMessage("Folder not found")
            except Exception:
                pass
        except PermissionError:
            self.pdf_label.setText(f"Error: No permission to access folder.\n{self.folder_path}")
            try:
                self.statusBar().showMessage("Permission denied")
            except Exception:
                pass

    def _restart_auto_refresh(self):
        """Helper to restart the auto-refresh timer after it was stopped."""
        if hasattr(self, 'auto_refresh_timer'):
            self.auto_refresh_timer.start(30000)  # Restart 30-second refresh
    
    def auto_refresh_file_list(self):
        """Automatically refresh file list to catch files added externally or by background processes.
        Only refreshes if no file is currently being viewed/edited to avoid disrupting user workflow."""
        try:
            # Don't refresh if user is actively working on a file
            if hasattr(self, 'current_file') and self.current_file:
                return  # Skip refresh entirely when viewing a document to prevent page jumps
            
            # Check if form has unsaved changes
            if hasattr(self, 'has_unsaved_changes') and getattr(self, 'has_unsaved_changes', False):
                return  # Skip refresh to avoid disrupting editing
            
            # Get current file list count before refresh
            old_count = self.file_list_widget.count()
            current_selection = self.file_list_widget.currentItem()
            current_filename = current_selection.text() if current_selection else None
            
            # Refresh the list
            self.load_file_list()
            
            # Get new count after refresh
            new_count = self.file_list_widget.count()
            
            # Restore selection if file still exists
            if current_filename:
                for i in range(self.file_list_widget.count()):
                    if self.file_list_widget.item(i).text() == current_filename:
                        self.file_list_widget.setCurrentRow(i)
                        break
            
            # Log if new files were detected
            if new_count > old_count:
                diff = new_count - old_count
                print(f"🔄 Auto-refresh detected {diff} new file{'s' if diff > 1 else ''}")
                
        except Exception as e:
            print(f"⚠️ Auto-refresh error: {e}")

    def print_file(self):
        """Print the current PDF file (current page)."""
        try:
            if not getattr(self, 'doc', None):
                QMessageBox.information(self, "Print", "No PDF is loaded to print.")
                return

            printer = QPrinter()
            dialog = QPrintDialog(printer, self)
            if dialog.exec() == QDialog.DialogCode.Accepted:
                # Render current page to a temporary image and send to printer
                tmp = os.path.join(os.getenv('TEMP', os.getcwd()), 'faxmanager_tmp_page.png')
                try:
                    self.doc.load_page(self.current_page_num).get_pixmap().save(tmp)
                    printer.setPageSize(QPrinter.PageSize.A4)
                    printer.setOrientation(QPrinter.Orientation.Portrait)
                    printer.setOutputFileName(tmp)
                    printer.setPrintRange(QPrinter.PrintRange.CurrentPage)
                    printer.print()
                finally:
                    try:
                        if os.path.exists(tmp):
                            os.remove(tmp)
                    except Exception:
                        pass
        except Exception as e:
            QMessageBox.warning(self, "Print", f"Failed to print: {e}")

    def download_current_pdf(self):
        """Copy the currently selected PDF to the user's Downloads folder with a safe filename.

        If a file with the same name exists, append a timestamp to avoid overwriting.
        """
        try:
            if not getattr(self, 'current_file', None):
                QMessageBox.information(self, "Download", "No file selected to download.")
                return

            # Clean filename - remove star prefix if present (consistent with other methods)
            clean_filename = self.current_file
            if clean_filename.startswith("★ "):
                clean_filename = clean_filename[2:]

            src_path = os.path.join(self.folder_path, clean_filename)
            if not os.path.exists(src_path):
                QMessageBox.warning(self, "Download", f"Source file not found:\n{src_path}")
                return

            downloads = os.path.join(os.path.expanduser("~"), "Downloads")
            try:
                os.makedirs(downloads, exist_ok=True)
            except Exception:
                downloads = self.folder_path

            base, ext = os.path.splitext(os.path.basename(clean_filename))
            dest_path = os.path.join(downloads, f"{base}{ext}")

            # If destination exists, add timestamp
            if os.path.exists(dest_path):
                ts = datetime.now().strftime("%Y%m%d_%H%M%S")
                dest_path = os.path.join(downloads, f"{base}_{ts}{ext}")

            shutil.copy2(src_path, dest_path)

            try:
                os.startfile(dest_path)
            except Exception:
                pass
            QMessageBox.information(self, "Download", f"Saved to: {dest_path}")
        except Exception as e:
            QMessageBox.critical(self, "Download", f"Failed to download file: {e}")

    def copy_file_path(self):
        """Copy the currently selected file's full path to the clipboard."""
        try:
            if not getattr(self, 'current_file', None):
                QMessageBox.information(self, "Copy Path", "No file selected.")
                return
            filepath = os.path.join(self.folder_path, self.current_file)
            QApplication.clipboard().setText(filepath)
            # Optional toast
            try:
                self.statusBar().showMessage("Path copied to clipboard", 2000)
            except Exception:
                pass
        except Exception as e:
            QMessageBox.warning(self, "Copy Path", f"Failed to copy: {e}")

