    def populate_patient_matches(self, combo: QComboBox, search_name: str):
        """Search patients database and populate combo with matches."""
        try:
            conn = sqlite3.connect(self.patients_database_file)
            cur = conn.cursor()
            cur.execute("""
                SELECT last_name, first_name, dob 
                FROM patients 
                WHERE UPPER(last_name) LIKE ? OR UPPER(first_name) LIKE ?
                ORDER BY last_name, first_name
                LIMIT 10
            """, (f'%{search_name.upper()}%', f'%{search_name.upper()}%'))
            
            matches = cur.fetchall()
            conn.close()
            
            for last, first, dob in matches:
                display = f"{last}, {first} (DOB: {dob})"
                combo.addItem(display, {'last': last, 'first': first, 'dob': dob})
                
        except Exception as e:
            print(f"Error searching patients: {e}")

    def populate_prescriber_matches(self, combo: QComboBox, search_name: str):
        """Search prescribers database and populate combo with matches."""
        try:
            conn = sqlite3.connect(self.prescriber_database_file)
            cur = conn.cursor()
            cur.execute("""
                SELECT name, npi 
                FROM prescribers 
                WHERE UPPER(name) LIKE ?
                ORDER BY name
                LIMIT 10
            """, (f'%{search_name.upper()}%',))
            
            matches = cur.fetchall()
            conn.close()
            
            for name, npi in matches:
                display = f"{name} (NPI: {npi})"
                combo.addItem(display, {'name': name, 'npi': npi})
                
        except Exception as e:
            print(f"Error searching prescribers: {e}")

    def populate_inventory_matches(self, combo: QComboBox, search_desc: str):
        """Search inventory database and populate combo with matches."""
        try:
            conn = sqlite3.connect(self.inventory_database_file)
            cur = conn.cursor()
            cur.execute("""
                SELECT hcpcs_code, description 
                FROM inventory 
                WHERE UPPER(description) LIKE ? OR UPPER(hcpcs_code) LIKE ?
                ORDER BY description
                LIMIT 10
            """, (f'%{search_desc.upper()}%', f'%{search_desc.upper()}%'))
            
            matches = cur.fetchall()
            conn.close()
            
            for hcpcs, desc in matches:
                display = f"{desc} ({hcpcs})"
                combo.addItem(display, {'hcpcs': hcpcs, 'description': desc})
                
        except Exception as e:
            print(f"Error searching inventory: {e}")

    def apply_extracted_data(self, dialog: QDialog):
        """Apply confirmed data to the document viewer fields."""
        try:
            fields = dialog.fields
            
            # === PATIENT INFORMATION ===
            # Patient name, DOB, and phone (for document viewer sidebar)
            if 'patient_first_name' in fields:
                self.first_name_input.setText(fields['patient_first_name'].currentText().upper())
            if 'patient_last_name' in fields:
                self.last_name_input.setText(fields['patient_last_name'].currentText().upper())
            if 'patient_dob' in fields:
                self.dob_input.setText(fields['patient_dob'].text())
            if 'patient_phone' in fields and hasattr(self, 'phone_input'):
                self.phone_input.setText(fields['patient_phone'].text())
            
            # Patient details (for order form) - try to find or create patient
            patient_name = f"{fields['patient_last_name'].currentText()}, {fields['patient_first_name'].currentText()}"
            try:
                # Check if patient exists in combo
                idx = self.patient_combo.findText(patient_name, Qt.MatchFlag.MatchContains)
                if idx >= 0:
                    self.patient_combo.setCurrentIndex(idx)
                else:
                    # Add as new patient entry (user can save to database later)
                    self.patient_combo.addItem(patient_name)
                    self.patient_combo.setCurrentText(patient_name)
            except Exception as e:
                print(f"Could not set patient combo: {e}")
            
            # === PRESCRIBER INFORMATION ===
            if 'prescriber_name' in fields and fields['prescriber_name'].currentText():
                prescriber_name = fields['prescriber_name'].currentText()
                try:
                    # Check if prescriber exists in combo
                    idx = self.prescriber_combo.findText(prescriber_name, Qt.MatchFlag.MatchContains)
                    if idx >= 0:
                        self.prescriber_combo.setCurrentIndex(idx)
                    else:
                        # Add as new prescriber entry
                        self.prescriber_combo.addItem(prescriber_name)
                        self.prescriber_combo.setCurrentText(prescriber_name)
                except Exception as e:
                    print(f"Could not set prescriber combo: {e}")
            
            # === ICD-10 DIAGNOSIS CODES ===
            # Only populate ICD codes if the fields exist (in Orders & Tracking tab)
            if hasattr(self, 'icd_code_1') and 'icd10_codes' in fields:
                icd_text = fields['icd10_codes'].toPlainText().strip()
                if icd_text:
                    # Parse comma-separated codes
                    codes = [code.strip().upper() for code in icd_text.replace(',', ' ').split() if code.strip()]
                    # Populate up to 5 ICD code fields
                    icd_fields = [self.icd_code_1, self.icd_code_2, self.icd_code_3, self.icd_code_4, self.icd_code_5]
                    for i, code in enumerate(codes[:5]):
                        if i < len(icd_fields):
                            icd_fields[i].setText(code)
            
            # === ITEMS/EQUIPMENT - Add to notes since items_table is in different tab ===
            items_summary = []
            if 'items_table' in fields:
                items_table = fields['items_table']
                
                # Collect items information
                for row in range(items_table.rowCount()):
                    desc_widget = items_table.cellWidget(row, 0)  # Description combo
                    qty_widget = items_table.cellWidget(row, 1)   # Quantity spinbox
                    
                    if desc_widget and desc_widget.currentText():
                        description = desc_widget.currentText()
                        quantity = qty_widget.value() if qty_widget else 1
                        
                        # Extract HCPCS code if present in description
                        import re
                        hcpcs_match = re.search(r'\(([A-Z0-9]+)\)', description)
                        hcpcs = hcpcs_match.group(1) if hcpcs_match else ''
                        
                        # Clean description (remove HCPCS code part if present)
                        clean_desc = re.sub(r'\s*\([A-Z0-9]+\)$', '', description).strip()
                        
                        # Build summary line
                        item_line = f"• {clean_desc}"
                        if hcpcs:
                            item_line += f" ({hcpcs})"
                        item_line += f" - Qty: {quantity}"
                        items_summary.append(item_line)
                
                # Add items to notes if any were extracted
                if items_summary and hasattr(self, 'new_note_input'):
                    items_note = "📦 OCR EXTRACTED ITEMS:\n" + "\n".join(items_summary)
                    current_notes = self.notes_history.toPlainText()
                    if current_notes:
                        self.notes_history.setPlainText(current_notes + "\n\n" + items_note)
                    else:
                        self.notes_history.setPlainText(items_note)
            
            # === PRESCRIBER INFORMATION - Add to notes for visibility ===
            if 'prescriber_name' in fields and fields['prescriber_name'].currentText():
                prescriber_name = fields['prescriber_name'].currentText()
                prescriber_npi = fields['prescriber_npi'].text() if 'prescriber_npi' in fields else ''
                
                prescriber_note = f"👨‍⚕️ OCR EXTRACTED PRESCRIBER:\n• {prescriber_name}"
                if prescriber_npi:
                    prescriber_note += f"\n• NPI: {prescriber_npi}"
                
                current_notes = self.notes_history.toPlainText()
                if current_notes:
                    self.notes_history.setPlainText(current_notes + "\n\n" + prescriber_note)
                else:
                    self.notes_history.setPlainText(prescriber_note)
            
            # Auto-save if current file is loaded
            if self.current_file:
                self.save_data(self.current_file)
            
            # Restart auto-refresh timer
            self._restart_auto_refresh()
            
            dialog.accept()
            
            # Show success message with summary
            summary = "✅ Data Applied Successfully!\n\n"
            summary += f"👤 Patient: {fields['patient_last_name'].currentText()}, {fields['patient_first_name'].currentText()}\n"
            summary += f"📅 DOB: {fields['patient_dob'].text()}\n"
            
            if 'prescriber_name' in fields and fields['prescriber_name'].currentText():
                summary += f"👨‍⚕️ Prescriber: {fields['prescriber_name'].currentText()}\n"
            
            if 'icd10_codes' in fields and fields['icd10_codes'].toPlainText().strip():
                icd_codes = fields['icd10_codes'].toPlainText().strip()
                summary += f"🏥 ICD-10: {icd_codes}\n"
            
            # Count items
            if 'items_table' in fields:
                items_table = fields['items_table']
                item_count = 0
                for row in range(items_table.rowCount()):
                    desc_widget = items_table.cellWidget(row, 0)
                    if desc_widget and desc_widget.currentText():
                        item_count += 1
                
                if item_count > 0:
                    summary += f"📦 Items: {item_count} item(s) added to order\n"
            
            QMessageBox.information(self, "✓ Data Applied", summary)
            self.statusBar().showMessage("✓ OCR data extracted and applied successfully", 5000)
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Error applying data: {e}\n\nPlease check the console for details.")
            print(f"Error applying extracted data: {e}")
            import traceback
            traceback.print_exc()

    # --- Basic viewer controls used by menu actions ---
    def zoom_in(self):
        """Zoom in the current PDF view."""
        try:
            self.zoom_level = min(getattr(self, 'zoom_level', 1.0) * 1.1, 5.0)
            if hasattr(self, 'render_page'):
                self.render_page()
        except Exception:
            pass

    def zoom_out(self):
        """Zoom out the current PDF view."""
        try:
            self.zoom_level = max(getattr(self, 'zoom_level', 1.0) / 1.1, 0.2)
            if hasattr(self, 'render_page'):
                self.render_page()
        except Exception:
            pass

    def fit_width(self):
        """Fit the current page to the viewport width."""
        try:
            if getattr(self, 'doc', None) and hasattr(self, 'scroll_area'):
                available_width = self.scroll_area.viewport().width() - 20
                page = self.doc.load_page(getattr(self, 'current_page_num', 0))
                self.zoom_level = available_width / page.rect.width
                self.render_page()
        except Exception:
            pass

    def prev_page(self):
        """Go to the previous page if available."""
        try:
            if getattr(self, 'doc', None) and getattr(self, 'current_page_num', 0) > 0:
                self.current_page_num -= 1
                self.render_page()
        except Exception:
            pass

    def next_page(self):
        """Go to the next page if available."""
        try:
            if getattr(self, 'doc', None):
                if self.current_page_num < len(self.doc) - 1:
                    self.current_page_num += 1
                    self.render_page()
        except Exception:
            pass

    def perform_search_from_drawer(self):
        """Execute search with the search worker thread."""
        try:
            # Validate folder path first
            if not hasattr(self, 'folder_path') or not self.folder_path:
                QMessageBox.warning(self, "Search Error", "No folder is currently selected.")
                return
            
            if not os.path.exists(self.folder_path):
                QMessageBox.warning(self, "Search Error", 
                                  f"The current folder does not exist:\n{self.folder_path}\n\n"
                                  "Please select a valid folder from Quick Folders.")
                return
            
            # Get search query
            q = self.search_input.text().strip() if hasattr(self, 'search_input') else ''
            if not q:
                QMessageBox.warning(self, "Search", "Please enter a search term.")
                return

            # Show progress
            if hasattr(self, 'search_progress'):
                self.search_progress.setVisible(True)
                self.search_progress.setValue(0)
            
            if hasattr(self, 'search_status_label'):
                self.search_status_label.setText("Searching...")

            # Clear previous results
            if hasattr(self, 'search_results_table'):
                self.search_results_table.clear()

            # Prepare search options
            search_options = {
                'search_metadata': True,
                'search_content': True,
                'filtered_files': None  # Search all files
            }

            # Create and start search worker
            self.search_worker = SearchWorker(self.folder_path, q, search_options)
            self.search_worker.progress.connect(self.on_search_progress)
            self.search_worker.finished.connect(self.on_search_finished)
            self.search_worker.error.connect(self.on_search_error)
            self.search_worker.start()

            self.statusBar().showMessage(f"Searching for '{q}'...")
            
        except Exception as e:
            QMessageBox.critical(self, "Search Error", f"Failed to start search: {e}")
            print(f"Search error: {e}")

    def on_search_progress(self, percent, current_file):
        """Update search progress."""
        if hasattr(self, 'search_progress'):
            self.search_progress.setValue(percent)
        if hasattr(self, 'search_status_label'):
            self.search_status_label.setText(f"Searching: {current_file}")

    def on_search_finished(self, results):
        """Handle search completion."""
        try:
            from PyQt6.QtWidgets import QTreeWidgetItem
            
            if hasattr(self, 'search_progress'):
                self.search_progress.setVisible(False)
            
            if hasattr(self, 'search_status_label'):
                self.search_status_label.setText(f"Found {len(results)} result(s)")

            self.statusBar().showMessage(f"Search complete: {len(results)} result(s) found", 5000)

            # Display results in tree widget
            if hasattr(self, 'search_results_table'):
                self.search_results_table.setSortingEnabled(False)
                self.search_results_table.clear()
                
                for result in results:
                    item = QTreeWidgetItem()
                    item.setText(0, result.get('filename', ''))
                    item.setText(1, str(result.get('page', 0) + 1))
                    item.setText(2, result.get('match_text', '')[:100])
                    item.setText(3, result.get('match_type', ''))
                    item.setData(0, Qt.ItemDataRole.UserRole, result)  # Store full result data
                    self.search_results_table.addTopLevelItem(item)
                
                self.search_results_table.setSortingEnabled(True)

            # Highlight files with results
            files_with_results = list(set(r['filename'] for r in results))
            self.highlight_files_with_results(files_with_results)

        except Exception as e:
            print(f"Error displaying search results: {e}")

    def on_search_error(self, error_msg):
        """Handle search error."""
        if hasattr(self, 'search_progress'):
            self.search_progress.setVisible(False)
        if hasattr(self, 'search_status_label'):
            self.search_status_label.setText("Search failed")
        QMessageBox.critical(self, "Search Error", f"Search failed: {error_msg}")
        self.statusBar().showMessage(f"Search error: {error_msg}", 5000)
    
    def browse_search_subfolder(self):
        """Browse and select a subfolder to search within."""
        try:
            start_folder = self.folder_path if hasattr(self, 'folder_path') and self.folder_path else os.path.expanduser("~")
            subfolder = QFileDialog.getExistingDirectory(
                self,
                "Select Folder to Search",
                start_folder,
                QFileDialog.Option.ShowDirsOnly
            )
            
            if subfolder:
                # Temporarily update folder_path for this search
                self.folder_path = subfolder
                self.statusBar().showMessage(f"Search folder set to: {os.path.basename(subfolder)}")
                # Optionally auto-trigger search
                # self.perform_search_from_drawer()
        except Exception as e:
            QMessageBox.warning(self, "Browse Error", f"Failed to browse folder: {e}")
            print(f"Browse subfolder error: {e}")

    def populate_fax_filter(self):
        """Populate fax filter combo with unique fax numbers parsed from filenames (best-effort)."""
        try:
            if not hasattr(self, 'fax_filter_combo'):
                return
            # Keep the first entry (All Fax Numbers)
            while self.fax_filter_combo.count() > 1:
                self.fax_filter_combo.removeItem(1)
            # Basic: just add distinct prefixes found in filenames like FAX_########
            nums = set()
            if os.path.isdir(self.folder_path):
                for name in os.listdir(self.folder_path):
                    if name.lower().endswith('.pdf'):
                        # crude parse
                        parts = name.split('_')
                        for p in parts:
                            if p.isdigit() and len(p) >= 7:
                                nums.add(p)
                                break
            for n in sorted(nums):
                self.fax_filter_combo.addItem(n, n)
        except Exception:
            pass

    def get_filtered_files(self):
        """Return PDF filenames filtered by current UI selections (best-effort fallback)."""
        try:
            pdfs = [f for f in os.listdir(self.folder_path) if f.lower().endswith('.pdf')]
        except Exception:
            return []
        # Fallback: no additional filtering here; main implementation elsewhere may be richer
        return pdfs

