    def clear_file_highlighting(self):
        """Remove any custom highlighting from the file list (no-op fallback)."""
        try:
            if hasattr(self, 'file_list_widget'):
                for i in range(self.file_list_widget.count()):
                    it = self.file_list_widget.item(i)
                    it.setBackground(QBrush())
                    it.setForeground(QBrush())
        except Exception:
            pass

    def highlight_files_with_results(self, files_with_results):
        """Apply simple highlight to files with results (fallback)."""
        try:
            if not hasattr(self, 'file_list_widget'):
                return
            target = set(files_with_results or [])
            for i in range(self.file_list_widget.count()):
                it = self.file_list_widget.item(i)
                name = it.text()
                if name in target:
                    it.setBackground(QBrush(QColor(255, 255, 0)))
                    it.setForeground(QBrush(QColor(0, 0, 0)))
                else:
                    it.setBackground(QBrush())
                    it.setForeground(QBrush())
        except Exception:
            pass

    def reapply_highlighting(self):
        """Reapply highlighting after list updates (fallback)."""
        # In this lightweight variant, the highlights are already applied directly
        pass

    def setup_persistent_highlighting(self):
        """Wire up selection change to reapply highlighting (fallback)."""
        try:
            if hasattr(self, 'file_list_widget'):
                self.file_list_widget.itemSelectionChanged.connect(self.on_selection_changed_highlight)
        except Exception:
            pass

    def on_selection_changed_highlight(self):
        """Reapply highlighting when selection changes (fallback)."""
        try:
            self.reapply_highlighting()
        except Exception:
            pass

    def on_file_selected(self, current_item, previous_item):
        """Handle selection change in the file list (save previous, load new)."""
        try:
            if previous_item is not None:
                try:
                    self.save_data(previous_item.text())
                except Exception:
                    pass
            # DON'T reset - we want to load data from database to keep tags attached to files
            # The load_data() call below will populate the fields with saved data
            if current_item is not None:
                self.current_file = current_item.text()
                # Load data FIRST to populate fields immediately
                try:
                    self.load_data(self.current_file)
                except Exception:
                    pass
                # Then display PDF (this can be slower)
                if hasattr(self, 'display_pdf'):
                    self.display_pdf(self.current_file)
        except Exception:
            pass

    def on_search_result_row_activated(self, item, column):
        """Open a search result when activated from the results table."""
        try:
            result = item.data(0, Qt.ItemDataRole.UserRole)
            if result:
                self.open_search_result(result)
        except Exception:
            pass

    def open_search_result(self, result):
        """Navigate to a result: select file and optionally page."""
        try:
            filename = result.get('filename') if isinstance(result, dict) else None
            page = result.get('page') if isinstance(result, dict) else None
            if not filename:
                return
            # Select in list
            if hasattr(self, 'file_list_widget'):
                for i in range(self.file_list_widget.count()):
                    it = self.file_list_widget.item(i)
                    if it.text() == filename or it.text().endswith(filename):
                        self.file_list_widget.setCurrentItem(it)
                        break
            # Display
            self.current_file = filename
            if hasattr(self, 'display_pdf'):
                self.display_pdf(filename)
            if isinstance(page, int) and page >= 0:
                self.current_page_num = page
                if hasattr(self, 'render_page'):
                    self.render_page()
        except Exception:
            pass

