    def check_for_updates_manual(self):
        """Manually check for application updates."""
        from dmelogic.update_checker import check_for_updates
        from dmelogic.ui.update_dialog import show_update_dialog, show_no_updates_dialog
        from PyQt6.QtWidgets import QApplication
        
        # Show busy cursor during check
        QApplication.setOverrideCursor(Qt.CursorShape.WaitCursor)
        
        try:
            update_info = check_for_updates()
        finally:
            QApplication.restoreOverrideCursor()
        
        if update_info:
            show_update_dialog(update_info, self)
        else:
            show_no_updates_dialog(self)
    
    def uninstall_application(self):
        """Launch the Windows uninstaller for this application."""
        try:
            import winreg
            import shutil
            
            # Confirm with user
            reply = QMessageBox.question(
                self,
                'Uninstall Application',
                'This will open the Windows uninstaller for DMELogic.\n\n'
                'Your data files (patients, orders, etc.) will NOT be deleted.\n'
                'You can back them up using File → Backup before uninstalling.\n\n'
                'Do you want to continue?',
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.No
            )
            
            if reply == QMessageBox.StandardButton.No:
                return
            
            # Clean up LocalAppData settings
            try:
                local_appdata = os.environ.get('LOCALAPPDATA', '')
                if local_appdata:
                    settings_dir = os.path.join(local_appdata, 'DMELogic')
                    if os.path.exists(settings_dir):
                        shutil.rmtree(settings_dir, ignore_errors=True)
                        print(f"Cleaned up settings folder: {settings_dir}")
            except Exception as e:
                print(f"Could not clean up settings: {e}")
            
            # Try to find the uninstaller in registry
            uninstall_path = None
            app_name = "DMELogic"
            
            # Search in both HKLM and HKCU uninstall keys
            registry_paths = [
                (winreg.HKEY_LOCAL_MACHINE, r"SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall"),
                (winreg.HKEY_CURRENT_USER, r"SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall"),
            ]
            
            for hkey, reg_path in registry_paths:
                try:
                    key = winreg.OpenKey(hkey, reg_path)
                    i = 0
                    while True:
                        try:
                            subkey_name = winreg.EnumKey(key, i)
                            subkey = winreg.OpenKey(key, subkey_name)
                            try:
                                display_name = winreg.QueryValueEx(subkey, "DisplayName")[0]
                                if app_name in display_name:
                                    uninstall_path = winreg.QueryValueEx(subkey, "UninstallString")[0]
                                    winreg.CloseKey(subkey)
                                    break
                            except:
                                pass
                            winreg.CloseKey(subkey)
                            i += 1
                        except OSError:
                            break
                    winreg.CloseKey(key)
                    if uninstall_path:
                        break
                except:
                    continue
            
            if uninstall_path:
                # Launch the uninstaller
                import subprocess
                subprocess.Popen(uninstall_path, shell=True)
                
                # Close the application
                QMessageBox.information(
                    self,
                    'Uninstaller Launched',
                    'The uninstaller has been launched.\n\n'
                    'This application will now close.'
                )
                self.close()
            else:
                # If not found in registry, open Windows Settings
                QMessageBox.information(
                    self,
                    'Manual Uninstall',
                    'Could not find the automatic uninstaller.\n\n'
                    'To uninstall manually:\n'
                    '1. Open Windows Settings (Win + I)\n'
                    '2. Go to Apps → Installed Apps\n'
                    '3. Search for "DMELogic"\n'
                    '4. Click the three dots and select "Uninstall"'
                )
                
        except Exception as e:
            QMessageBox.warning(
                self,
                'Error',
                f'Could not launch uninstaller: {str(e)}\n\n'
                'To uninstall manually:\n'
                '1. Open Windows Settings (Win + I)\n'
                '2. Go to Apps → Installed Apps\n'
                '3. Search for "DME Solutions v1"\n'
                '4. Click Uninstall'
            )
        
    def setup_database(self):
        """Creates the database and table if they don't exist."""
        # Create the folder if it doesn't exist
        if not os.path.exists(self.folder_path):
            os.makedirs(self.folder_path, exist_ok=True)
            print(f"Created folder: {self.folder_path}")
    
        conn = sqlite3.connect(self.database_file)
        cursor = conn.cursor()
        cursor.execute("""
        CREATE TABLE IF NOT EXISTS documents (
            filename TEXT PRIMARY KEY,
            first_name TEXT,
            last_name TEXT,
            dob TEXT,
            notes TEXT
        )
        """)
        conn.commit()
        conn.close()

    def setup_patient_database(self):
        """Creates the patient database and table if they don't exist."""
        # Patient database file
        self.patient_database_file = self.resolve_db_path("patients.db")
        # Fallback to creating in db_folder or app directory if not found
        if not self.patient_database_file:
            db_folder = self.settings.get('db_folder') if hasattr(self, 'settings') else None
            if db_folder and os.path.exists(db_folder):
                self.patient_database_file = os.path.join(db_folder, "patients.db")
            else:
                app_root = os.path.dirname(os.path.abspath(__file__))
                self.patient_database_file = os.path.join(app_root, "patients.db")
        self.patient_db_path = self.patient_database_file
        
        conn = sqlite3.connect(self.patient_database_file)
        cursor = conn.cursor()
        cursor.execute("""
        CREATE TABLE IF NOT EXISTS patients (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            last_name TEXT NOT NULL,
            first_name TEXT NOT NULL,
            dob TEXT,
            gender TEXT,
            ssn TEXT,
            phone TEXT,
            secondary_contact TEXT,
            address TEXT,
            city TEXT,
            state TEXT,
            zip TEXT,
            primary_insurance TEXT,
            policy_number TEXT,
            group_number TEXT,
            secondary_insurance TEXT,
            secondary_insurance_id TEXT,
            notes TEXT,
            created_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
        """)
        
        # Add new columns if they don't exist (for existing databases)
        try:
            cursor.execute("ALTER TABLE patients ADD COLUMN secondary_insurance_id TEXT")
            print("✅ Added secondary_insurance_id column to existing database")
        except sqlite3.OperationalError:
            pass
        try:
            cursor.execute("ALTER TABLE patients ADD COLUMN gender TEXT")
            print("✅ Added gender column to existing database")
        except sqlite3.OperationalError:
            pass
        
        try:
            cursor.execute("ALTER TABLE patients ADD COLUMN secondary_contact TEXT")
            print("✅ Added secondary_contact column to existing database")
        except sqlite3.OperationalError:
            pass
        
        try:
            cursor.execute("ALTER TABLE patients ADD COLUMN notes TEXT")
            print("✅ Added notes column to existing database")
        except sqlite3.OperationalError:
            pass
        
        conn.commit()
        conn.close()
        print(f"✅ Patient database initialized: {self.patient_database_file}")

