    def load_supplier_names(self, combo: QComboBox):
        """Populate a combo box with supplier names from suppliers DB."""
        try:
            combo.blockSignals(True)
            combo.clear()
            conn = sqlite3.connect(self.suppliers_database_file)
            cur = conn.cursor()
            cur.execute("SELECT name FROM suppliers ORDER BY UPPER(name)")
            names = cur.fetchall()
            conn.close()
            for (name,) in names:
                if name and str(name).strip():
                    combo.addItem(str(name).strip())
        except Exception as e:
            print(f"Error loading supplier names: {e}")
        finally:
            try:
                combo.blockSignals(False)
            except Exception:
                pass

    def load_category_names(self, combo: QComboBox):
        """Populate a combo box with inventory category names from categories master table.

        Falls back to distinct values from inventory table if master table is unavailable.
        """
        try:
            combo.blockSignals(True)
            combo.clear()
            names: list[str] = []
            try:
                conn = sqlite3.connect(self.inventory_database_file)
                cur = conn.cursor()
                # Prefer master table if exists
                cur.execute("""
                    SELECT name FROM sqlite_master WHERE type='table' AND name='inventory_categories'
                """)
                if cur.fetchone():
                    cur.execute("SELECT name FROM inventory_categories WHERE active=1 ORDER BY UPPER(name)")
                    names = [r[0] for r in cur.fetchall() if r[0] and str(r[0]).strip()]
                else:
                    cur.execute("""
                        SELECT DISTINCT TRIM(category) FROM inventory
                        WHERE category IS NOT NULL AND TRIM(category) <> ''
                        ORDER BY UPPER(TRIM(category))
                    """)
                    names = [r[0] for r in cur.fetchall() if r[0] and str(r[0]).strip()]
                conn.close()
            except Exception as e:
                print(f"Error loading categories: {e}")
            # Add items
            for name in names:
                combo.addItem(str(name).strip())
        finally:
            try:
                combo.blockSignals(False)
            except Exception:
                pass

    def save_category_name(self, name: str):
        """Insert category name into master table if not present."""
        try:
            if not name or not str(name).strip():
                return
            name = str(name).strip()
            conn = sqlite3.connect(self.inventory_database_file)
            cur = conn.cursor()
            # Ensure table exists
            cur.execute("""
                CREATE TABLE IF NOT EXISTS inventory_categories (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    name TEXT UNIQUE NOT NULL,
                    active INTEGER DEFAULT 1,
                    sort_order INTEGER,
                    created_date TEXT DEFAULT (datetime('now')),
                    updated_date TEXT DEFAULT (datetime('now'))
                )
            """)
            cur.execute("INSERT OR IGNORE INTO inventory_categories(name) VALUES (?)", (name,))
            conn.commit()
            conn.close()
        except Exception as e:
            print(f"Error saving category name: {e}")

