                table.setItem(row, 0, QTableWidgetItem(prescriber_name or "N/A"))
                table.setItem(row, 1, QTableWidgetItem(npi or "N/A"))
                table.setItem(row, 2, QTableWidgetItem(specialty))
                table.setItem(row, 3, QTableWidgetItem(formatted_date))
            
