    def create_insurance_combo(self, field_name):
        """Create a combo box for insurance names with auto-complete."""
        combo = QComboBox()
        combo.setEditable(True)
        combo.setInsertPolicy(QComboBox.InsertPolicy.NoInsert)
        
        # Style the combo box
        combo.setStyleSheet("""
            QComboBox {
                background-color: #3C3C3C;
                border: 1px solid #555555;
                border-radius: 4px;
                padding: 5px;
                color: white;
                font-size: 12px;
            }
            QComboBox:focus {
                border: 2px solid #0078D4;
            }
            QComboBox::drop-down {
                border: none;
                background-color: #424242;
                width: 20px;
            }
            QComboBox::down-arrow {
                image: none;
                border-left: 5px solid transparent;
                border-right: 5px solid transparent;
                border-top: 5px solid white;
                margin: 5px;
            }
            QComboBox QAbstractItemView {
                background-color: #2B2B2B;
                border: 1px solid #424242;
                selection-background-color: #0078D4;
                color: white;
            }
        """)
        
        # Load existing insurance names
        self.load_insurance_names(combo)
        
        # Auto-uppercase conversion
        line_edit = combo.lineEdit()
        if line_edit:
            line_edit.textChanged.connect(lambda text: self.convert_combo_to_uppercase(combo, text))
        
        return combo
    
    def convert_combo_to_uppercase(self, combo, text):
        """Convert combo box text to uppercase."""
        if text != text.upper():
            # Preserve cursor position
            line_edit = combo.lineEdit()
            cursor_pos = line_edit.cursorPosition()
            combo.setEditText(text.upper())
            line_edit.setCursorPosition(cursor_pos)
    
    def load_insurance_names(self, combo):
        """Load insurance names from database into combo box."""
        try:
            conn = sqlite3.connect(self.insurance_database_file)
            cursor = conn.cursor()
            cursor.execute("""
                SELECT name FROM insurance_names 
                ORDER BY usage_count DESC, name ASC
            """)
            
            names = cursor.fetchall()
            conn.close()
            
            combo.clear()
            combo.addItem("")  # Empty option
            
            for name_tuple in names:
                name = name_tuple[0]
                if name.strip():  # Only add non-empty names
                    combo.addItem(name)
            
        except Exception as e:
            print(f"Error loading insurance names: {e}")
    
    def save_insurance_name(self, name):
        """Save insurance name to database or increment usage count."""
        if not name or not name.strip():
            return
        
        name = name.strip().upper()
        
        try:
            conn = sqlite3.connect(self.insurance_database_file)
            cursor = conn.cursor()
            
            # Check if name already exists
            cursor.execute("SELECT id, usage_count FROM insurance_names WHERE name = ?", (name,))
            existing = cursor.fetchone()
            
            if existing:
                # Update usage count and last used date
                cursor.execute("""
                    UPDATE insurance_names 
                    SET usage_count = usage_count + 1, last_used = CURRENT_TIMESTAMP 
                    WHERE id = ?
                """, (existing[0],))
            else:
                # Insert new insurance name
                cursor.execute("""
                    INSERT INTO insurance_names (name) VALUES (?)
                """, (name,))
            
            conn.commit()
            conn.close()
            
        except Exception as e:
            print(f"Error saving insurance name: {e}")
    
    def refresh_insurance_combos(self):
        """Refresh all insurance combo boxes with updated data."""
        try:
            if hasattr(self, 'patient_fields'):
                for field_name in ['primary_insurance', 'secondary_insurance']:
                    if field_name in self.patient_fields:
                        combo = self.patient_fields[field_name]
                        current_text = combo.currentText()
                        self.load_insurance_names(combo)
                        combo.setEditText(current_text)
        except Exception as e:
            print(f"Error refreshing insurance combos: {e}")

    # ===== RX numbering helpers (moved from ToggleSwitch) =====
    def get_next_rx_no(self) -> int:
        """Atomically allocate and return the next available RX number.

        First checks for gaps in the sequence (deleted/unused RX numbers),
        then falls back to incrementing from the last_rx_no counter.
        Uses orders.db tables rx_control (single-row counter) and rx_log.
        """
        try:
            conn = sqlite3.connect(self.orders_db_path)
            cur = conn.cursor()
            # Session cache to avoid handing out the same RX multiple times in one run
            session_reserved = set(getattr(self, "_reserved_rx_in_session", set()))
            
            # Get baseline: current max allocated
            cur.execute("SELECT last_rx_no FROM rx_control LIMIT 1")
            row = cur.fetchone()
            last = int(row[0]) if row and row[0] is not None else 1000

            # 1) Prefer reusing any previously reserved (allocated) numbers that are not actually used
            #    and not already taken during this session.
            try:
                cur.execute(
                    """
                    SELECT r.rx_no
                    FROM rx_log r
                    LEFT JOIN order_items oi ON CAST(oi.rx_no AS INTEGER) = r.rx_no
                    WHERE r.action = 'allocated' AND (oi.rx_no IS NULL OR TRIM(oi.rx_no) = '')
                    ORDER BY r.rx_no ASC
                    """
                )
                rows_alloc = [int(str(x[0])) for x in cur.fetchall() if str(x[0]).strip().isdigit()]
            except Exception:
                rows_alloc = []

            for candidate in rows_alloc:
                if candidate not in session_reserved:
                    next_no = candidate
                    # mark session-reserved to avoid giving it again during this run
                    try:
                        if not hasattr(self, '_reserved_rx_in_session'):
                            self._reserved_rx_in_session = set()
                        self._reserved_rx_in_session.add(int(candidate))
                    except Exception:
                        pass
                    conn.commit(); conn.close()
                    return next_no

            # 2) Otherwise, compute numerical gaps considering only actually used numbers
            used_rx = set()
            # From rx_log, only 'used'
            try:
                cur.execute("SELECT rx_no FROM rx_log WHERE action = 'used' ORDER BY rx_no")
                used_rx.update(int(r[0]) for r in cur.fetchall())
            except Exception:
                pass
            # From order_items
            cur.execute("SELECT DISTINCT CAST(rx_no AS INTEGER) FROM order_items WHERE rx_no IS NOT NULL AND TRIM(rx_no) != '' AND TRIM(rx_no) GLOB '[0-9]*'")
            for row in cur.fetchall():
                try:
                    used_rx.add(int(row[0]))
                except Exception:
                    pass

            next_no = None
            for candidate in range(1001, last + 2):
                if (candidate not in used_rx) and (candidate not in session_reserved):
                    next_no = candidate
                    break

            # 3) If no gap found, increment from last
            if next_no is None:
                next_no = last + 1

            # Update control only if we're using a number beyond current last
            if next_no > last:
                cur.execute("UPDATE rx_control SET last_rx_no = ?", (next_no,))

            # Maintain session cache and record allocation (order_item_id will be linked on save)
            try:
                if not hasattr(self, '_reserved_rx_in_session'):
                    self._reserved_rx_in_session = set()
                self._reserved_rx_in_session.add(int(next_no))
            except Exception:
                pass

            try:
                cur.execute(
                    "INSERT OR IGNORE INTO rx_log (rx_no, action, note) VALUES (?, 'allocated', 'allocated in dialog')",
                    (next_no,)
                )
            except Exception:
                pass

            conn.commit()
            conn.close()
            return next_no
        except Exception as e:
            print(f"RX allocation error: {e}")
            return 0

    def link_rx_to_order(self, order_id: int, rx_numbers: list[int]):
        """Mark RX numbers as used and associate them to an order."""
        try:
            if not rx_numbers:
                return
            conn = sqlite3.connect(self.orders_db_path)
            cur = conn.cursor()
            for rx in rx_numbers:
                try:
                    rx_i = int(str(rx))
                except Exception:
                    continue
                cur.execute(
                    "UPDATE rx_log SET order_id = ?, action = 'used' WHERE rx_no = ?",
                    (int(order_id), rx_i),
                )
                if cur.rowcount == 0:
                    # If not pre-allocated record, insert now
                    cur.execute(
                        "INSERT OR REPLACE INTO rx_log (rx_no, order_id, action, note) VALUES (?, ?, 'used', 'linked on save')",
                        (rx_i, int(order_id)),
                    )
            conn.commit()
            conn.close()
        except Exception as e:
            print(f"RX link error: {e}")

    def _orders_db_path(self) -> str:
        """Resolve orders.db path using settings['db_folder'] or a safe default."""
        try:
            base = None
            if isinstance(getattr(self, "settings", None), dict):
                base = self.settings.get("db_folder")
            if not base:
                base = _default_db_folder()
            os.makedirs(base, exist_ok=True)
            return os.path.join(base, "orders.db")
        except Exception:
            return os.path.join(os.getcwd(), "orders.db")

    def log_rx_deleted_for_order(self, order_id: int):
        """When an order is deleted, mark its RX numbers as deleted in rx_log."""
        try:
            conn = sqlite3.connect(self.orders_db_path)
            cur = conn.cursor()
            cur.execute("SELECT rx_no FROM order_items WHERE order_id = ?", (int(order_id),))
            rows = cur.fetchall()
            rx_list = []
            for r in rows:
                num = r[0]
                try:
                    rx_i = int(str(num))
                except Exception:
                    continue
                rx_list.append(rx_i)
            for rx in rx_list:
                cur.execute(
                    "UPDATE rx_log SET action = 'deleted' WHERE rx_no = ?",
                    (rx,)
                )
                if cur.rowcount == 0:
                    cur.execute(
                        "INSERT OR REPLACE INTO rx_log (rx_no, order_id, action, note) VALUES (?, ?, 'deleted', 'order deleted')",
                        (rx, int(order_id)),
                    )
            conn.commit()
            conn.close()
        except Exception as e:
            print(f"RX delete log error: {e}")

    def log_deleted_order(self, order_id: int):
        """
        Log complete order and items to deleted_orders and deleted_order_items tables before deletion.
        Preserves full order details for audit trail and potential recovery.
        """
        try:
            conn = sqlite3.connect(self.orders_db_path)
            cursor = conn.cursor()
            
            # Get order data
            cursor.execute("""
                SELECT id, rx_date, order_date, patient_last_name, patient_first_name, patient_dob,
                       patient_address, patient_phone, patient_secondary_contact,
                       icd_code_1, icd_code_2, icd_code_3, icd_code_4, icd_code_5,
                       prescriber_name, prescriber_npi,
                       primary_insurance, primary_insurance_id, secondary_insurance, secondary_insurance_id,
                       billing_selection, order_status, delivery_date, tracking_number,
                       parent_order_id, refill_number, billed, paid, paid_date, notes,
                       is_pickup, pickup_date, doctor_directions
                FROM orders WHERE id = ?
            """, (order_id,))
            order_row = cursor.fetchone()
            
            if not order_row:
                print(f"Order {order_id} not found for deletion logging")
                conn.close()
                return
            
            # Determine who deleted it (if auth system is active)
            deleted_by = "Unknown"
            if hasattr(self, 'auth_system') and hasattr(self.auth_system, 'current_user'):
                deleted_by = self.auth_system.current_user or "Unknown"
            
            # Insert order data into deleted_orders
            cursor.execute("""
                INSERT INTO deleted_orders (
                    original_order_id, rx_date, order_date, patient_last_name, patient_first_name,
                    patient_dob, patient_address, patient_phone, patient_secondary_contact,
                    icd_code_1, icd_code_2, icd_code_3, icd_code_4, icd_code_5,
                    prescriber_name, prescriber_npi,
                    primary_insurance, primary_insurance_id, secondary_insurance, secondary_insurance_id,
                    billing_selection, order_status, delivery_date, tracking_number,
                    parent_order_id, refill_number, billed, paid, paid_date, notes,
                    is_pickup, pickup_date, doctor_directions, deleted_by
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """, (order_row[0], order_row[1], order_row[2], order_row[3], order_row[4],
                  order_row[5], order_row[6], order_row[7], order_row[8],
                  order_row[9], order_row[10], order_row[11], order_row[12], order_row[13],
                  order_row[14], order_row[15],
                  order_row[16], order_row[17], order_row[18], order_row[19],
                  order_row[20], order_row[21], order_row[22], order_row[23],
                  order_row[24], order_row[25], order_row[26], order_row[27], order_row[28], order_row[29],
                  order_row[30], order_row[31], order_row[32], deleted_by))
            
            deleted_order_id = cursor.lastrowid
            
            # Get and insert order items
            cursor.execute("""
                SELECT id, rx_no, hcpcs_code, description, item_number, refills, day_supply, 
                       qty, cost_ea, total, pa_number, directions
                FROM order_items WHERE order_id = ?
            """, (order_id,))
            
            items = cursor.fetchall()
            for item in items:
                cursor.execute("""
                    INSERT INTO deleted_order_items (
                        deleted_order_id, original_item_id, rx_no, hcpcs_code, description,
                        item_number, refills, day_supply, qty, cost_ea, total, pa_number, directions
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """, (deleted_order_id, item[0], item[1], item[2], item[3],
                      item[4], item[5], item[6], item[7], item[8], item[9], item[10], item[11]))
            
            conn.commit()
            conn.close()
            
            print(f"✅ Order {order_id} logged to deleted_orders table (deleted by: {deleted_by})")
            
        except Exception as e:
            print(f"Error logging deleted order: {e}")
            try:
                conn.close()
            except:
                pass

    def get_deleted_rx_numbers(self):
        """
        Dynamically determine RX numbers available for reuse.
        Combines:
          - Explicitly logged deleted RX numbers (if any)
          - Automatically detected unused RX numbers in DB range
        Returns a list of tuples: (rx_no, deleted_on, note)
        """
        import sqlite3
        from datetime import datetime

        available = []
        deleted_log = set()
        allocated_log = set()
        session_reserved = set(getattr(self, "_reserved_rx_in_session", set()))
        try:
            # Determine orders.db path
            db_path = getattr(self, "orders_db_path", None)
            if not db_path and hasattr(self, "settings") and isinstance(self.settings, dict):
                db_path = self.settings.get("orders_db_path") or self.settings.get("db_folder")
            if db_path and os.path.isdir(db_path):
                db_path = os.path.join(db_path, "orders.db")

            used_rx = set()
            last_rx_from_ctrl = None
            if db_path and os.path.exists(db_path):
                conn = sqlite3.connect(db_path)
                cur = conn.cursor()

                # 1) Include any explicitly logged deletions
                # Preferred: rx_log with action='deleted'
                try:
                    cur.execute("SELECT rx_no, created_at, note FROM rx_log WHERE action = 'deleted' ORDER BY rx_no")
                    for rx_no, created_at, note in cur.fetchall():
                        try:
                            rx_i = int(rx_no)
                        except Exception:
                            continue
                        deleted_log.add(rx_i)
                        available.append((rx_i, created_at or "", note or ""))
                except sqlite3.Error:
                    pass
                # Legacy/back-compat: deleted_rx_numbers table if present
                try:
                    cur.execute("SELECT rx_no, deleted_on, note FROM deleted_rx_numbers ORDER BY rx_no")
                    for rx_no, deleted_on, note in cur.fetchall():
                        try:
                            rx_i = int(rx_no)
                        except Exception:
                            continue
                        deleted_log.add(rx_i)
                        available.append((rx_i, deleted_on or "", note or ""))
                except sqlite3.Error:
                    pass  # table may not exist

                # Track reserved (allocated) so we don't show them as available
                try:
                    cur.execute("SELECT rx_no FROM rx_log WHERE action = 'allocated'")
                    allocated_log = {int(r[0]) for r in cur.fetchall() if str(r[0]).isdigit()}
                except sqlite3.Error:
                    pass

                # Try to get last_rx_no from rx_control for window centering
                try:
                    cur.execute("SELECT last_rx_no FROM rx_control LIMIT 1")
                    row = cur.fetchone()
                    if row and row[0] is not None:
                        last_rx_from_ctrl = int(row[0])
                except sqlite3.Error:
                    pass

                # Collect used RXs from order_items
                try:
                    cur.execute("SELECT rx_no FROM order_items WHERE rx_no IS NOT NULL AND TRIM(rx_no) <> ''")
                    used_rx = {int(str(row[0]).strip()) for row in cur.fetchall() if str(row[0]).strip().isdigit()}
                except Exception:
                    used_rx = set()

                conn.close()

        except Exception as e:
            print(f"Error determining available RX numbers: {e}")

        # 2) Auto-detect gaps (unused RX numbers in a tighter, sensible window)
        try:
            if last_rx_from_ctrl is not None and used_rx:
                # Center window around last_rx_no: show nearby unused numbers
                min_rx = max(1, last_rx_from_ctrl - 50)
                max_rx = last_rx_from_ctrl + 50
            elif used_rx:
                min_rx = max(1, min(used_rx) - 10)
                max_rx = max(used_rx) + 30
            elif last_rx_from_ctrl is not None:
                # No used RX yet, but we have a control baseline: offer a small window below last_rx_no
                min_rx = max(1, last_rx_from_ctrl - 10)
                max_rx = max(0, last_rx_from_ctrl - 1)
                if min_rx > max_rx:
                    raise RuntimeError("no-window")
            else:
                # No data to infer from
                raise RuntimeError("no-used-rx")

            all_rx = set(range(min_rx, max_rx + 1))
            unused_rx = sorted(all_rx - used_rx - deleted_log - allocated_log - session_reserved)
            today = datetime.now().strftime("%Y-%m-%d")
            for rx_no in unused_rx:
                available.append((rx_no, today, "Auto-detected unused number"))
        except Exception:
            # Only explicit deletions will be shown when we can't derive gaps
            pass

        # Return sorted unique list, excluding reserved (allocated)
        unique = {}
        for rx_no, deleted_on, note in available:
            try:
                rx_i = int(rx_no)
                if rx_i in allocated_log or rx_i in session_reserved:
                    continue
                unique[rx_i] = (deleted_on, note)
            except Exception:
                continue
        return [(rx, deleted_on, note) for rx, (deleted_on, note) in sorted(unique.items())]

    def get_reserved_rx_numbers(self):
        """Return a list of (rx_no, reserved_on, note) for RXs currently reserved (allocated)."""
        rows = []
        try:
            db_path = getattr(self, "orders_db_path", None)
            if db_path and os.path.exists(db_path):
                conn = sqlite3.connect(db_path)
                cur = conn.cursor()
                cur.execute("SELECT rx_no, created_at, note FROM rx_log WHERE action = 'allocated' ORDER BY created_at DESC")
                rows = [
                    (int(str(rx).strip()), created_at or "", note or "")
                    for (rx, created_at, note) in cur.fetchall()
                    if str(rx).strip().isdigit()
                ]
                conn.close()
        except Exception as e:
            print(f"Error reading reserved RX numbers: {e}")
        return rows

