    def update_page_navigation(self):
        """Update 'Page X / Y' label and navigation buttons."""
        try:
            if not hasattr(self, "page_label"):
                return
            text = f"Page {self.current_page_num + 1} / {self.total_pages}" if self.total_pages else "Page 0 / 0"
            self.page_label.setText(text)
            self.prev_page_btn.setEnabled(self.current_page_num > 0)
            self.next_page_btn.setEnabled(self.current_page_num + 1 < self.total_pages)
        except Exception as e:
            print("update_page_navigation error:", e)

    def update_order_status(self):
        """Update the status of the selected order."""
        current_row = self.orders_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an order first.")
            return

        order_number = self.orders_table.item(current_row, 0).text()
        order_id_val = self.get_order_id_from_display(order_number)
        if not order_id_val:
            QMessageBox.warning(self, "Invalid Order", "Couldn't determine the order ID.")
            return
        order_id = int(order_id_val)

        # Get current status
        try:
            conn = sqlite3.connect(self.orders_db_path)
            cursor = conn.cursor()
            cursor.execute("SELECT order_status FROM orders WHERE id = ?", (order_id,))
            row = cursor.fetchone()
            current_status = row[0] if row else "Pending"
            conn.close()
        except Exception:
            current_status = "Pending"

        # Show status selection dialog
        statuses = ["Pending", "In Progress", "Ready for Delivery", "Delivered", "Completed", "Cancelled"]
        status, ok = QInputDialog.getItem(
            self,
            "Update Order Status",
            f"Select new status for {order_number}:",
            statuses,
            statuses.index(current_status) if current_status in statuses else 0,
            False
        )

        if ok and status:
            try:
                conn = sqlite3.connect(self.orders_db_path)
                cursor = conn.cursor()
                cursor.execute("UPDATE orders SET order_status = ? WHERE id = ?", (status, order_id))
                conn.commit()
                conn.close()

                # Refresh table
                self.load_orders()
                if current_row < self.orders_table.rowCount():
                    self.orders_table.selectRow(current_row)
                QMessageBox.information(self, "Success", f"Order {order_number} status updated to: {status}")
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to update status: {e}")

    def show_delivery_report(self):
        """Show a report of orders filtered by delivery status."""
        try:
            conn = sqlite3.connect(self.orders_db_path)
            cursor = conn.cursor()
            
            # Get delivered orders
            cursor.execute("""
                SELECT id, rx_date, order_date, patient_last_name, patient_first_name,
                       order_status, delivery_date, tracking_number
                FROM orders
                WHERE delivery_date IS NOT NULL
                ORDER BY delivery_date DESC
            """)
            delivered = cursor.fetchall()
            
            # Get pending deliveries
            cursor.execute("""
                SELECT id, rx_date, order_date, patient_last_name, patient_first_name,
                       order_status, tracking_number
                FROM orders
                WHERE delivery_date IS NULL AND order_status NOT IN ('Cancelled', 'Completed')
                ORDER BY order_date ASC
            """)
            pending = cursor.fetchall()
            conn.close()

            # Create report dialog
            dialog = QDialog(self)
            dialog.setWindowTitle("📊 Delivery Report")
            dialog.resize(900, 600)
            layout = QVBoxLayout(dialog)

            # Summary stats
            stats_label = QLabel(f"<b>Total Delivered:</b> {len(delivered)} | <b>Pending Delivery:</b> {len(pending)}")
            stats_label.setStyleSheet("font-size: 14px; padding: 10px; background: #f0f0f0; border-radius: 5px;")
            layout.addWidget(stats_label)

            # Tab widget for delivered vs pending
            tabs = QTabWidget()
            
            # Delivered tab
            delivered_table = QTableWidget()
            delivered_table.setColumnCount(7)
            delivered_table.setHorizontalHeaderLabels(["Order #", "Patient", "Order Date", "Delivery Date", "Status", "Tracking", "RX Date"])
            delivered_table.setRowCount(len(delivered))
            
            for i, order in enumerate(delivered):
                order_id, rx_date, order_date, last_name, first_name, status, delivery_date, tracking = order
                delivered_table.setItem(i, 0, QTableWidgetItem(self.format_order_number(order_id)))
                delivered_table.setItem(i, 1, QTableWidgetItem(f"{last_name}, {first_name}"))
                delivered_table.setItem(i, 2, QTableWidgetItem(order_date or ""))
                delivered_table.setItem(i, 3, QTableWidgetItem(delivery_date or ""))
                delivered_table.setItem(i, 4, QTableWidgetItem(status or ""))
                delivered_table.setItem(i, 5, QTableWidgetItem(tracking or ""))
                delivered_table.setItem(i, 6, QTableWidgetItem(rx_date or ""))
            
            delivered_table.resizeColumnsToContents()
            tabs.addTab(delivered_table, f"Delivered ({len(delivered)})")
            
            # Pending tab
            pending_table = QTableWidget()
            pending_table.setColumnCount(6)
            pending_table.setHorizontalHeaderLabels(["Order #", "Patient", "Order Date", "Status", "Tracking", "RX Date"])
            pending_table.setRowCount(len(pending))
            
            for i, order in enumerate(pending):
                order_id, rx_date, order_date, last_name, first_name, status, tracking = order
                pending_table.setItem(i, 0, QTableWidgetItem(self.format_order_number(order_id)))
                pending_table.setItem(i, 1, QTableWidgetItem(f"{last_name}, {first_name}"))
                pending_table.setItem(i, 2, QTableWidgetItem(order_date or ""))
                pending_table.setItem(i, 3, QTableWidgetItem(status or ""))
                pending_table.setItem(i, 4, QTableWidgetItem(tracking or ""))
                pending_table.setItem(i, 5, QTableWidgetItem(rx_date or ""))
            
            pending_table.resizeColumnsToContents()
            tabs.addTab(pending_table, f"Pending Delivery ({len(pending)})")
            
            layout.addWidget(tabs)
            
            # Close button
            close_btn = QPushButton("Close")
            close_btn.clicked.connect(dialog.accept)
            layout.addWidget(close_btn)
            
            dialog.exec()
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to generate delivery report: {e}")
            print(f"Delivery report error: {e}")

