    def load_queues_list(self):
        """Load all workflow queues into the left list."""
        try:
            self.queues_list.clear()
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            cur.execute("""
                SELECT id, queue_name, description, color, icon, 
                       (SELECT COUNT(*) FROM queue_items WHERE queue_id = workflow_queues.id) as item_count
                FROM workflow_queues
                WHERE is_active = 1
                ORDER BY sort_order ASC, queue_name ASC
            """)
            rows = cur.fetchall()
            conn.close()
            
            for queue_id, name, desc, color, icon, count in rows:
                display_text = f"{icon} {name} ({count})"
                item = QListWidgetItem(display_text)
                item.setData(Qt.ItemDataRole.UserRole, queue_id)
                item.setForeground(QColor(color or '#FFFFFF'))
                self.queues_list.addItem(item)
            
            if rows:
                self.queues_list.setCurrentRow(0)
        except Exception as e:
            self.queue_status.setText(f"Error loading queues: {e}")

    def on_queue_selected(self):
        """Load items for the selected queue."""
        current = self.queues_list.currentItem()
        if not current:
            self.queue_title_label.setText("Select a queue")
            self.add_to_queue_btn.setEnabled(False)
            self.remove_from_queue_btn.setEnabled(False)
            self.open_order_from_queue_btn.setEnabled(False)
            self.queue_items_table.setRowCount(0)
            return
        
        queue_id = current.data(Qt.ItemDataRole.UserRole)
        queue_name = current.text().split('(')[0].strip()
        self.queue_title_label.setText(f"📋 {queue_name}")
        self.add_to_queue_btn.setEnabled(True)
        self.load_queue_items(queue_id)

    def load_queue_items(self, queue_id):
        """Load all orders assigned to this queue."""
        try:
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            cur.execute("""
                SELECT qi.id, qi.order_id, qi.priority, qi.assigned_to, qi.notes,
                       o.patient_first_name, o.patient_last_name, o.order_date, o.order_status
                FROM queue_items qi
                JOIN orders o ON qi.order_id = o.id
                WHERE qi.queue_id = ?
                ORDER BY 
                    CASE qi.priority 
                        WHEN 'Urgent' THEN 1 
                        WHEN 'High' THEN 2 
                        WHEN 'Normal' THEN 3 
                        WHEN 'Low' THEN 4 
                        ELSE 5 
                    END,
                    qi.added_date DESC
            """, (queue_id,))
            rows = cur.fetchall()
            conn.close()
            
            self.queue_items_table.setRowCount(0)
            for qi_id, order_id, priority, assigned_to, notes, fn, ln, order_date, status in rows:
                row_idx = self.queue_items_table.rowCount()
                self.queue_items_table.insertRow(row_idx)
                
                patient = f"{ln}, {fn}".strip(', ')
                
                items = [
                    str(order_id),
                    patient,
                    order_date or '',
                    status or '',
                    priority or 'Normal',
                    assigned_to or '',
                    (notes or '')[:50]
                ]
                
                for col, val in enumerate(items):
                    item = QTableWidgetItem(val)
                    item.setData(Qt.ItemDataRole.UserRole, (qi_id, order_id))
                    
                    # Color code by priority
                    if col == 4:
                        if priority == 'Urgent':
                            item.setForeground(QColor('#e74c3c'))
                        elif priority == 'High':
                            item.setForeground(QColor('#f39c12'))
                    
                    # Color code status
                    if col == 3:
                        if status == 'Pending':
                            item.setForeground(QColor('#f39c12'))
                        elif status == 'Completed':
                            item.setForeground(QColor('#2ecc71'))
                    
                    self.queue_items_table.setItem(row_idx, col, item)
            
            self.queue_status.setText(f"Loaded {len(rows)} items in queue")
        except Exception as e:
            self.queue_status.setText(f"Error loading queue items: {e}")

    def on_queue_item_selected(self):
        """Enable/disable buttons based on selection."""
        has_selection = len(self.queue_items_table.selectedItems()) > 0
        self.remove_from_queue_btn.setEnabled(has_selection)
        self.open_order_from_queue_btn.setEnabled(has_selection)

