    def edit_selected_queue(self):
        """Open dialog to edit the selected queue."""
        current = self.queues_list.currentItem()
        if not current:
            QMessageBox.warning(self, "No Selection", "Please select a queue to edit.")
            return
        
        queue_id = current.data(Qt.ItemDataRole.UserRole)
        
        try:
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            cur.execute("""
                SELECT id, queue_name, description, color, icon, sort_order
                FROM workflow_queues WHERE id = ?
            """, (queue_id,))
            row = cur.fetchone()
            conn.close()
            
            if row:
                existing = {
                    'id': row[0],
                    'name': row[1],
                    'description': row[2],
                    'color': row[3],
                    'icon': row[4],
                    'sort_order': row[5]
                }
                self.open_queue_dialog(existing)
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load queue: {e}")

    def delete_selected_queue(self):
        """Delete the selected workflow queue."""
        current = self.queues_list.currentItem()
        if not current:
            QMessageBox.warning(self, "No Selection", "Please select a queue to delete.")
            return
        
        queue_id = current.data(Qt.ItemDataRole.UserRole)
        queue_name = current.text().split('(')[0].strip()
        
        confirm = QMessageBox.question(
            self,
            "Confirm Delete",
            f"Delete queue '{queue_name}'?\n\nThis will remove all items from this queue.",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No
        )
        
        if confirm == QMessageBox.StandardButton.Yes:
            try:
                conn = sqlite3.connect(self.orders_database_file)
                cur = conn.cursor()
                cur.execute("DELETE FROM queue_items WHERE queue_id = ?", (queue_id,))
                cur.execute("DELETE FROM workflow_queues WHERE id = ?", (queue_id,))
                conn.commit()
                conn.close()
                self.load_queues_list()
                QMessageBox.information(self, "Success", f"Queue '{queue_name}' deleted successfully.")
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to delete queue: {e}")

    def open_queue_dialog(self, existing=None):
        """Open dialog to create/edit a queue."""
        from PyQt6.QtWidgets import QDialog, QVBoxLayout, QFormLayout, QLineEdit, QTextEdit, QSpinBox, QPushButton, QHBoxLayout, QColorDialog
        
        dialog = QDialog(self)
        dialog.setWindowTitle("New Queue" if not existing else "Edit Queue")
        dialog.setMinimumWidth(500)
        
        layout = QVBoxLayout(dialog)
        form = QFormLayout()
        
        name_input = QLineEdit()
        name_input.setText(existing['name'] if existing else "")
        form.addRow("Queue Name*:", name_input)
        
        desc_input = QTextEdit()
        desc_input.setMaximumHeight(80)
        desc_input.setText(existing['description'] if existing else "")
        form.addRow("Description:", desc_input)
        
        icon_input = QLineEdit()
        icon_input.setText(existing['icon'] if existing else "📋")
        icon_input.setMaxLength(2)
        form.addRow("Icon (emoji):", icon_input)
        
        color_layout = QHBoxLayout()
        color_input = QLineEdit()
        color_input.setText(existing['color'] if existing else "#0078D4")
        color_layout.addWidget(color_input)
        color_btn = QPushButton("Choose Color")
        
        def choose_color():
            color = QColorDialog.getColor(QColor(color_input.text()), dialog, "Choose Queue Color")
            if color.isValid():
                color_input.setText(color.name())
        
        color_btn.clicked.connect(choose_color)
        color_layout.addWidget(color_btn)
        form.addRow("Color:", color_layout)
        
        sort_input = QSpinBox()
        sort_input.setMinimum(0)
        sort_input.setMaximum(999)
        sort_input.setValue(existing['sort_order'] if existing else 0)
        form.addRow("Sort Order:", sort_input)
        
        layout.addLayout(form)
        
        btn_layout = QHBoxLayout()
        btn_layout.addStretch()
        cancel_btn = QPushButton("Cancel")
        cancel_btn.clicked.connect(dialog.reject)
        btn_layout.addWidget(cancel_btn)
        
        save_btn = QPushButton("Save")
        save_btn.setStyleSheet("background:#27ae60;color:white;padding:6px 16px")
        save_btn.clicked.connect(dialog.accept)
        btn_layout.addWidget(save_btn)
        layout.addLayout(btn_layout)
        
        if dialog.exec() == QDialog.DialogCode.Accepted:
            name = name_input.text().strip()
            if not name:
                QMessageBox.warning(self, "Validation", "Queue name is required.")
                return
            
            data = {
                'name': name,
                'description': desc_input.toPlainText().strip(),
                'icon': icon_input.text().strip() or "📋",
                'color': color_input.text().strip() or "#0078D4",
                'sort_order': sort_input.value()
            }
            
            try:
                conn = sqlite3.connect(self.orders_database_file)
                cur = conn.cursor()
                
                if existing:
                    cur.execute("""
                        UPDATE workflow_queues 
                        SET queue_name = ?, description = ?, icon = ?, color = ?, sort_order = ?, updated_date = CURRENT_TIMESTAMP
                        WHERE id = ?
                    """, (data['name'], data['description'], data['icon'], data['color'], data['sort_order'], existing['id']))
                else:
                    cur.execute("""
                        INSERT INTO workflow_queues (queue_name, description, icon, color, sort_order)
                        VALUES (?, ?, ?, ?, ?)
                    """, (data['name'], data['description'], data['icon'], data['color'], data['sort_order']))
                
                conn.commit()
                conn.close()
                self.load_queues_list()
                QMessageBox.information(self, "Success", "Queue saved successfully.")
            except sqlite3.IntegrityError:
                QMessageBox.warning(self, "Duplicate", f"A queue named '{name}' already exists.")
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to save queue: {e}")

    def add_order_to_queue(self):
        """Add an order to the currently selected queue."""
        current_queue = self.queues_list.currentItem()
        if not current_queue:
            return
        
        queue_id = current_queue.data(Qt.ItemDataRole.UserRole)
        
        from PyQt6.QtWidgets import QDialog, QVBoxLayout, QFormLayout, QLineEdit, QComboBox, QTextEdit, QPushButton, QHBoxLayout, QLabel
        
        dialog = QDialog(self)
        dialog.setWindowTitle("Add Order to Queue")
        dialog.setMinimumWidth(450)
        
        layout = QVBoxLayout(dialog)
        form = QFormLayout()
        
        order_id_input = QLineEdit()
        order_id_input.setPlaceholderText("Enter order ID")
        form.addRow("Order ID*:", order_id_input)
        
        priority_input = QComboBox()
        priority_input.addItems(["Normal", "Urgent", "High", "Low"])
        form.addRow("Priority:", priority_input)
        
        assigned_input = QLineEdit()
        assigned_input.setPlaceholderText("Assigned to (optional)")
        form.addRow("Assigned To:", assigned_input)
        
        notes_input = QTextEdit()
        notes_input.setMaximumHeight(80)
        notes_input.setPlaceholderText("Notes (optional)")
        form.addRow("Notes:", notes_input)
        
        layout.addLayout(form)
        
        btn_layout = QHBoxLayout()
        btn_layout.addStretch()
        cancel_btn = QPushButton("Cancel")
        cancel_btn.clicked.connect(dialog.reject)
        btn_layout.addWidget(cancel_btn)
        
        add_btn = QPushButton("Add to Queue")
        add_btn.setStyleSheet("background:#27ae60;color:white;padding:6px 16px")
        add_btn.clicked.connect(dialog.accept)
        btn_layout.addWidget(add_btn)
        layout.addLayout(btn_layout)
        
        if dialog.exec() == QDialog.DialogCode.Accepted:
            try:
                order_id = int(order_id_input.text().strip())
            except ValueError:
                QMessageBox.warning(self, "Invalid Input", "Please enter a valid order ID.")
                return
            
            # Verify order exists
            try:
                conn = sqlite3.connect(self.orders_database_file)
                cur = conn.cursor()
                cur.execute("SELECT id FROM orders WHERE id = ?", (order_id,))
                if not cur.fetchone():
                    conn.close()
                    QMessageBox.warning(self, "Not Found", f"Order #{order_id} not found.")
                    return
                
                # Add to queue
                cur.execute("""
                    INSERT INTO queue_items (queue_id, order_id, priority, assigned_to, notes)
                    VALUES (?, ?, ?, ?, ?)
                """, (queue_id, order_id, priority_input.currentText(), assigned_input.text().strip(), notes_input.toPlainText().strip()))
                
                conn.commit()
                conn.close()
                
                self.load_queue_items(queue_id)
                self.load_queues_list()  # Refresh count
                QMessageBox.information(self, "Success", f"Order #{order_id} added to queue.")
            except sqlite3.IntegrityError:
                QMessageBox.warning(self, "Duplicate", f"Order #{order_id} is already in this queue.")
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to add order to queue: {e}")

