    def load_tasks_table(self):
        """Load tasks from database applying simple filters."""
        try:
            assignee = self.tasks_assignee_filter.currentText() if hasattr(self, 'tasks_assignee_filter') else 'All Assignees'
            status = self.tasks_status_filter.currentText() if hasattr(self, 'tasks_status_filter') else 'All Statuses'
            priority = self.tasks_priority_filter.currentText() if hasattr(self, 'tasks_priority_filter') else 'All Priorities'
            clauses = []
            params = []
            if assignee and assignee != 'All Assignees':
                if assignee == 'Me':
                    clauses.append("assigned_to_user = ?"); params.append('Me')
                else:
                    clauses.append("assigned_to_user = ?"); params.append(assignee)
            if status and status != 'All Statuses':
                clauses.append("status = ?"); params.append(status)
            if priority and priority != 'All Priorities':
                clauses.append("priority = ?"); params.append(priority)
            where = ("WHERE " + " AND ".join(clauses)) if clauses else ""
            q = f"""
                SELECT id, title, status, priority, due_date, assigned_to_user, notes, completed_date, patient_name
                FROM tasks
                {where}
                ORDER BY COALESCE(due_date,'9999-12-31') ASC, priority DESC, created_date DESC
                LIMIT 500
            """
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            cur.execute(q, params)
            rows = cur.fetchall()
            conn.close()
            self.tasks_table.setRowCount(0)
            for r in rows:
                tid, title, status_v, priority_v, due, assigned, notes, completed, patient = r
                row = self.tasks_table.rowCount(); self.tasks_table.insertRow(row)
                completed_flag = '✔' if status_v == 'Completed' or completed else ''
                color = '#95a5a6' if completed_flag else ('#e74c3c' if due and due < datetime.now().strftime('%Y-%m-%d') and status_v != 'Completed' else ('#f39c12' if due == datetime.now().strftime('%Y-%m-%d') else 'white'))
                values = [str(tid), completed_flag, priority_v, due or '', title, patient or '', assigned or '', status_v]
                for col, val in enumerate(values):
                    item = QTableWidgetItem(val)
                    if col in (3,4):
                        item.setForeground(QColor(color))
                    self.tasks_table.setItem(row, col, item)
            self.tasks_status_label.setText(f"Loaded {len(rows)} tasks")
        except Exception as e:
            self.tasks_status_label.setText(f"Error loading tasks: {e}")

    def open_task_dialog(self, existing: dict | None = None):
        dlg = TaskDialog(self, existing)
        if dlg.exec() == QDialog.DialogCode.Accepted:
            data = dlg.get_data()
            self.save_task(data)
            self.load_tasks_table()

    def edit_selected_task(self, *_):
        row = self.tasks_table.currentRow()
        if row < 0:
            return
        tid_item = self.tasks_table.item(row, 0)
        if not tid_item:
            return
        tid = tid_item.text()
        try:
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            cur.execute("SELECT id, title, status, priority, due_date, assigned_to_user, notes FROM tasks WHERE id = ?", (tid,))
            r = cur.fetchone(); conn.close()
            if not r:
                return
            existing = {
                'id': r[0], 'title': r[1], 'status': r[2], 'priority': r[3], 'due_date': r[4], 'assigned_to_user': r[5], 'notes': r[6]
            }
            self.open_task_dialog(existing)
        except Exception as e:
            QMessageBox.critical(self, "Tasks", f"Failed to load task: {e}")

    def save_task(self, data: dict):
        try:
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            if data.get('id'):
                cur.execute("""
                    UPDATE tasks SET title=?, status=?, priority=?, due_date=?, assigned_to_user=?, notes=?,
                        completed_date = CASE WHEN ?='Completed' THEN COALESCE(completed_date, CURRENT_TIMESTAMP)
                                             WHEN ?!='Completed' THEN NULL ELSE completed_date END
                    WHERE id=?
                """, (data['title'], data['status'], data['priority'], data['due_date'], data['assigned_to_user'], data['notes'], data['status'], data['status'], data['id']))
            else:
                cur.execute("""
                    INSERT INTO tasks (title,status,priority,due_date,assigned_to_user,notes)
                    VALUES (?,?,?,?,?,?)
                """, (data['title'], data['status'], data['priority'], data['due_date'], data['assigned_to_user'], data['notes']))
            conn.commit(); conn.close()
        except Exception as e:
            QMessageBox.critical(self, "Tasks", f"Failed to save task: {e}")

    def show_tasks_context_menu(self, position):
        """Show context menu for tasks table."""
        row = self.tasks_table.currentRow()
        if row < 0:
            return
        
        menu = QMenu()
        edit_action = menu.addAction("✏️ Edit Task")
        complete_action = menu.addAction("✅ Mark as Completed")
        menu.addSeparator()
        delete_action = menu.addAction("🗑️ Delete Task")
        
        action = menu.exec(self.tasks_table.viewport().mapToGlobal(position))
        
        if action == edit_action:
            self.edit_selected_task()
        elif action == complete_action:
            self.mark_task_completed()
        elif action == delete_action:
            self.delete_selected_task()

