    def load_data(self, filename):
        """Loads data from the database into the input fields."""
        if not filename:
            return
        
        # Clean filename - remove star prefix if present
        clean_filename = filename
        if clean_filename.startswith("★ "):
            clean_filename = clean_filename[2:]
        
        try:
            conn = sqlite3.connect(self.database_file)
            cursor = conn.cursor()
            
            # Check if phone column exists
            cursor.execute("PRAGMA table_info(documents)")
            columns = [col[1] for col in cursor.fetchall()]
            has_phone = 'phone' in columns
            
            if has_phone:
                cursor.execute("SELECT first_name, last_name, dob, phone, notes FROM documents WHERE filename=?", (clean_filename,))
            else:
                cursor.execute("SELECT first_name, last_name, dob, notes FROM documents WHERE filename=?", (clean_filename,))
            
            row = cursor.fetchone()
            if row:
                if has_phone:
                    self.first_name_input.setText(row[0] or "")
                    self.last_name_input.setText(row[1] or "")
                    self.dob_input.setText(row[2] or "")
                    if hasattr(self, 'phone_input'):
                        self.phone_input.setText(row[3] or "")
                    self.notes_history.setText(row[4] or "")
                else:
                    self.first_name_input.setText(row[0] or "")
                    self.last_name_input.setText(row[1] or "")
                    self.dob_input.setText(row[2] or "")
                    if hasattr(self, 'phone_input'):
                        self.phone_input.clear()
                    self.notes_history.setText(row[3] or "")
            else:
                # Clear fields if no data found
                self.first_name_input.clear()
                self.last_name_input.clear()
                self.dob_input.clear()
                if hasattr(self, 'phone_input'):
                    self.phone_input.clear()
                self.notes_history.clear()
            conn.close()
        except Exception as e:
            print(f"Error loading data for {clean_filename}: {e}")

    def load_inventory_data(self):
        """Load inventory data from database into the table."""
        try:
            conn = sqlite3.connect(self.inventory_database_file)
            cursor = conn.cursor()
            cursor.execute("""
                SELECT item_id, hcpcs_code, description, category, cost, 
                       retail_price, brand, supplier, stock_quantity, reorder_level,
                       last_used_date, last_restocked_date
                FROM inventory 
                ORDER BY description
            """)
            items = cursor.fetchall()
            conn.close()
            
            self.inventory_table.setRowCount(len(items))
            for row, item in enumerate(items):
                for col, value in enumerate(item):
                    # Format currency columns
                    if col in [4, 5] and value is not None:  # Cost and Retail Price
                        display_value = f"${float(value):.2f}"
                    elif col in [10, 11]:  # Date columns
                        display_value = str(value) if value else "Never"
                    else:
                        display_value = str(value) if value is not None else ""
                    
                    self.inventory_table.setItem(row, col, QTableWidgetItem(display_value))
            
            # Update status (indexes 8 and 9 are stock and reorder level)
            low_stock_count = sum(
                1 for item in items
                if item[8] is not None and item[9] is not None and item[8] <= item[9]
            )
            status_text = f"Loaded {len(items)} inventory items"
            if low_stock_count > 0:
                status_text += f" | ⚠️ {low_stock_count} items low stock"
            self.inventory_status.setText(status_text)
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load inventory data: {e}")
            self.inventory_status.setText("Error loading inventory data")

    def render_page(self):
        """Render the current page as an image and display."""
        if not getattr(self, "doc", None):
            return
        if not hasattr(self, "total_pages") or self.total_pages <= 0:
            self.total_pages = self.doc.page_count if hasattr(self.doc, "page_count") else len(self.doc)
        if self.current_page_num < 0 or self.current_page_num >= self.total_pages:
            return

        page = self.doc.load_page(self.current_page_num)
        mat = fitz.Matrix(self.zoom_level, self.zoom_level).prerotate(self.rotation_angle)
        pix = page.get_pixmap(matrix=mat)
        image = QImage(pix.samples, pix.width, pix.height, pix.stride, QImage.Format.Format_RGB888)
        pixmap = QPixmap.fromImage(image)
        
        self.pdf_label.setPixmap(pixmap)
        self.pdf_label.resize(pixmap.size())
        self.update_page_navigation()

    def _handle_pdf_label_click(self, event):
        """Handle mouse clicks on PDF to detect link clicks."""
        if hasattr(self, 'current_page_links') and self.current_page_links:
            click_x = event.pos().x()
            click_y = event.pos().y()
            
            # Check if click is within any link rectangle
            for link in self.current_page_links:
                x0, y0, x1, y1 = link['rect']
                if x0 <= click_x <= x1 and y0 <= click_y <= y1:
                    # Open the link
                    import webbrowser
                    webbrowser.open(link['uri'])
                    print(f"Opening link: {link['uri']}")
                    return
        
        # Call original mouse press event if it exists
        QLabel.mousePressEvent(self.pdf_label, event)

