    def generate_patient_report(self):
        """Generate patient analytics report from patients.db."""
        try:
            import sqlite3
            # ISO for DB filtering
            start_date = self.report_start_date.date().toString("yyyy-MM-dd") if hasattr(self, 'report_start_date') else None
            end_date = self.report_end_date.date().toString("yyyy-MM-dd") if hasattr(self, 'report_end_date') else None
            # Pretty for display
            start_display = self.report_start_date.date().toString("MM/dd/yyyy") if hasattr(self, 'report_start_date') else None
            end_display = self.report_end_date.date().toString("MM/dd/yyyy") if hasattr(self, 'report_end_date') else None

            conn = sqlite3.connect(self.patient_database_file)
            cur = conn.cursor()
            # Totals
            cur.execute("SELECT COUNT(*) FROM patients")
            total_patients = cur.fetchone()[0]

            # New patients in range (based on created_date if available)
            new_in_range = None
            if start_date and end_date:
                try:
                    cur.execute("SELECT COUNT(*) FROM patients WHERE date(created_date) BETWEEN date(?) AND date(?)", (start_date, end_date))
                    new_in_range = cur.fetchone()[0]
                except Exception:
                    new_in_range = None

            # Top insurances by count
            cur.execute("SELECT COALESCE(primary_insurance, ''), COUNT(*) as c FROM patients GROUP BY primary_insurance ORDER BY c DESC LIMIT 5")
            top_ins = cur.fetchall()
            conn.close()

            lines = []
            lines.append("Patient Analytics Report")
            if start_date and end_date:
                lines.append(f"Date range: {start_display} to {end_display}")
            lines.append("")
            lines.append(f"Total patients: {total_patients}")
            if new_in_range is not None:
                lines.append(f"New patients in range: {new_in_range}")
            lines.append("")
            lines.append("Top Insurances:")
            if top_ins:
                for name, c in top_ins:
                    label = name if name else "(Unspecified)"
                    lines.append(f"  • {label}: {c}")
            else:
                lines.append("  • No insurance data available")

            self.reports_text.setPlainText("\n".join(lines))
            if hasattr(self, 'update_reports_visuals'):
                self.update_reports_visuals(report_type="patients")
        except Exception as e:
            import traceback
            error_msg = f"Error generating patient report:\n{str(e)}\n\n{traceback.format_exc()}"
            self.reports_text.setPlainText(error_msg)
            QMessageBox.critical(self, "Report Error", f"Failed to generate patient report:\n\n{str(e)}")
    
